import { Material, HistoryItem, Exam } from '../types';

const DB_NAME = 'PersonaLearnDB';
const STORE_MATERIALS = 'materials';
const DB_VERSION = 1;

// Helper to open DB
const openDB = (): Promise<IDBDatabase> => {
  return new Promise((resolve, reject) => {
    const request = indexedDB.open(DB_NAME, DB_VERSION);
    request.onerror = () => reject(request.error);
    request.onsuccess = () => resolve(request.result);
    request.onupgradeneeded = (event) => {
      const db = (event.target as IDBOpenDBRequest).result;
      if (!db.objectStoreNames.contains(STORE_MATERIALS)) {
        db.createObjectStore(STORE_MATERIALS, { keyPath: 'id' });
      }
    };
  });
};

export const StorageService = {
  // LocalStorage wrappers for lightweight JSON data
  getHistory: (role: string): HistoryItem[] => {
    const data = localStorage.getItem(`history_${role}`);
    return data ? JSON.parse(data) : [];
  },

  addHistoryItem: (role: string, item: HistoryItem) => {
    const history = StorageService.getHistory(role);
    const newHistory = [item, ...history];
    localStorage.setItem(`history_${role}`, JSON.stringify(newHistory));
  },

  deleteHistoryItem: (role: string, id: string) => {
    const history = StorageService.getHistory(role);
    const newHistory = history.filter(item => item.id !== id);
    localStorage.setItem(`history_${role}`, JSON.stringify(newHistory));
  },

  getExams: (role: string): Exam[] => {
    const data = localStorage.getItem(`exams_${role}`);
    // Mock data if empty
    if (!data) {
       const mock: Exam[] = [
           { id: '1', title: 'Calculus I Midterm', subject: 'Math', date: '2024-05-20', durationMinutes: 90, status: 'SCHEDULED' },
           { id: '2', title: 'Physics Finals', subject: 'Physics', date: '2024-06-10', durationMinutes: 120, status: 'SCHEDULED' }
       ];
       return mock;
    }
    return JSON.parse(data);
  },

  saveExam: (role: string, exam: Exam) => {
    const exams = StorageService.getExams(role);
    localStorage.setItem(`exams_${role}`, JSON.stringify([...exams, exam]));
  },

  // IndexedDB wrappers for large files (Materials)
  saveMaterial: async (material: Material): Promise<void> => {
    const db = await openDB();
    const tx = db.transaction(STORE_MATERIALS, 'readwrite');
    const store = tx.objectStore(STORE_MATERIALS);
    store.put(material);
    return new Promise((resolve, reject) => {
        tx.oncomplete = () => resolve();
        tx.onerror = () => reject(tx.error);
    });
  },

  getAllMaterials: async (): Promise<Material[]> => {
    const db = await openDB();
    const tx = db.transaction(STORE_MATERIALS, 'readonly');
    const store = tx.objectStore(STORE_MATERIALS);
    const request = store.getAll();
    return new Promise((resolve, reject) => {
      request.onsuccess = () => resolve(request.result);
      request.onerror = () => reject(request.error);
    });
  }
};

import { GoogleGenAI, Type } from "@google/genai";

const getAI = () => {
    // In a real app, handle missing key gracefully
    const apiKey = process.env.API_KEY || ''; 
    return new GoogleGenAI({ apiKey });
};

export const GeminiService = {
  summarize: async (text: string): Promise<string> => {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: `Summarize the following text concisely for a student study aid:\n\n${text}`,
    });
    return response.text || "Could not generate summary.";
  },

  generateFlashcards: async (content: string): Promise<any[]> => {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: `Create 5 study flashcards from the following content. Return valid JSON.`,
      config: {
        responseMimeType: 'application/json',
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              front: { type: Type.STRING },
              back: { type: Type.STRING },
            },
            required: ['front', 'back']
          },
        },
      },
    });

    try {
        return JSON.parse(response.text || '[]');
    } catch (e) {
        console.error("Failed to parse flashcards", e);
        return [];
    }
  },

  generateQA: async (content: string): Promise<any> => {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: `Generate a Q&A set from this content. Include 2 Multiple Choice, 2 Short Answer, and 1 Long Answer questions.`,
      config: {
        responseMimeType: 'application/json',
        responseSchema: {
            type: Type.OBJECT,
            properties: {
                mcq: { 
                    type: Type.ARRAY, 
                    items: { 
                        type: Type.OBJECT,
                        properties: {
                            question: { type: Type.STRING },
                            options: { type: Type.ARRAY, items: { type: Type.STRING }},
                            correctAnswer: { type: Type.STRING }
                        }
                    }
                },
                shortAnswer: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            question: { type: Type.STRING },
                            answer: { type: Type.STRING }
                        }
                    }
                },
                longAnswer: {
                     type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            question: { type: Type.STRING },
                            answer: { type: Type.STRING }
                        }
                    }
                }
            }
        }
      }
    });
    try {
        return JSON.parse(response.text || '{}');
    } catch (e) {
        return {};
    }
  },

  generateMindMap: async (content: string): Promise<string> => {
    const ai = getAI();
    const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: `Create a mermaid.js mindmap syntax for the following content. Only return the code starting with 'mindmap'. Do not include markdown ticks. \n\n${content}`
    });
    let text = response.text || '';
    // Clean up potential markdown code blocks
    text = text.replace(/```mermaid/g, '').replace(/```/g, '').trim();
    return text;
  },

  runCode: async (code: string, language: string): Promise<string> => {
     const ai = getAI();
     const response = await ai.models.generateContent({
         model: 'gemini-2.5-flash',
         contents: `Act as a code execution engine. Simulate the output of the following ${language} code. 
         If there is an error, describe it. Only provide the output, no conversational filler.

         Code:
         ${code}`
     });
     return response.text || "No output.";
  },

  generatePaper: async (topic: string, grade: string): Promise<any> => {
     const ai = getAI();
     const response = await ai.models.generateContent({
         model: 'gemini-2.5-flash',
         contents: `Create a question paper for Grade ${grade} on the topic: ${topic}.`,
         config: {
            responseMimeType: 'application/json',
            responseSchema: {
                type: Type.OBJECT,
                properties: {
                    title: { type: Type.STRING },
                    duration: { type: Type.STRING },
                    sections: {
                        type: Type.ARRAY,
                        items: {
                            type: Type.OBJECT,
                            properties: {
                                name: { type: Type.STRING },
                                questions: { 
                                    type: Type.ARRAY,
                                    items: { type: Type.STRING }
                                }
                            }
                        }
                    }
                }
            }
         }
     });
     try {
         return JSON.parse(response.text || '{}');
     } catch (e) {
         return null;
     }
  },

  getImprovementAreas: async (): Promise<any[]> => {
      const ai = getAI();
      const response = await ai.models.generateContent({
          model: 'gemini-2.5-flash',
          contents: "Analyze a hypothetical student's recent poor performance in Calculus (Derivatives) and Physics (Kinematics). Suggest 3 specific areas for improvement.",
           config: {
            responseMimeType: 'application/json',
            responseSchema: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: {
                        topic: { type: Type.STRING },
                        suggestion: { type: Type.STRING },
                        priority: { type: Type.STRING }
                    }
                }
            }
           }
      });
      try {
        return JSON.parse(response.text || '[]');
      } catch (e) {
          return [];
      }
  }
};

