const TeacherMaterialGenerator: React.FC = () => {
    const [topic, setTopic] = useState('');
    const [grade, setGrade] = useState('10');
    const [loading, setLoading] = useState(false);
    const [result, setResult] = useState<any>(null);

    const handleGenerate = async () => {
        setLoading(true);
        const res = await GeminiService.generatePaper(topic, grade);
        setResult(res);
        setLoading(false);
        if (res) {
             StorageService.addHistoryItem('TEACHER', {
                 id: Date.now().toString(),
                 type: 'PAPER',
                 title: `Exam: ${topic} (Grade ${grade})`,
                 content: res,
                 createdAt: Date.now()
             });
        }
    };

    const handleSchedule = () => {
        if (!result) return;
        StorageService.saveExam('TEACHER', {
            id: Date.now().toString(),
            title: result.title,
            subject: topic,
            date: new Date(Date.now() + 86400000).toISOString().split('T')[0],
            durationMinutes: 60,
            status: 'SCHEDULED'
        });
        alert('Exam Scheduled successfully!');
    };

    return (
        <div className="space-y-4">
            <div className="grid grid-cols-1 md:grid-cols-4 gap-4 items-end">
                <div className="md:col-span-2">
                    <Label>Topic / Subject</Label>
                    <Input value={topic} onChange={e => setTopic(e.target.value)} placeholder="e.g. Thermodynamics, World War II" />
                </div>
                <div>
                    <Label>Grade Level</Label>
                    <Select value={grade} onChange={e => setGrade(e.target.value)}>
                        <option value="8">Grade 8</option>
                        <option value="9">Grade 9</option>
                        <option value="10">Grade 10</option>
                        <option value="11">Grade 11</option>
                        <option value="12">Grade 12</option>
                    </Select>
                </div>
                <Button onClick={handleGenerate} loading={loading}>Generate Paper</Button>
            </div>

            {result && (
                <div className="mt-6 p-4 bg-background border border-border rounded-xl">
                    <div className="flex justify-between items-center mb-4 pb-4 border-b border-border">
                         <h3 className="text-xl font-bold">{result.title}</h3>
                         <Button variant="secondary" onClick={handleSchedule} size="sm">Schedule This Exam</Button>
                    </div>
                    <div className="space-y-6">
                        {result.sections?.map((section: any, i: number) => (
                            <div key={i}>
                                <h4 className="text-secondary font-medium mb-2 uppercase text-sm tracking-wider">{section.name}</h4>
                                <ul className="list-decimal list-inside space-y-2 text-muted-foreground">
                                    {section.questions.map((q: string, idx: number) => (
                                        <li key={idx} className="text-gray-300">{q}</li>
                                    ))}
                                </ul>
                            </div>
                        ))}
                    </div>
                </div>
            )}
        </div>
    );
};

import React, { useState } from 'react';
import Layout from './components/Layout';
import { Persona } from './types';
import { StudentDashboard, StudentTools } from './views/Student';
import { TeacherDashboard } from './views/Teacher';
import { InstitutionDashboard } from './views/Institution';
import CodePlayground from './components/CodePlayground';

const App: React.FC = () => {
  const [currentPersona, setCurrentPersona] = useState<Persona>('STUDENT');
  const [activeView, setActiveView] = useState('dashboard');
  const [lang, setLang] = useState('en');

  const renderContent = () => {
    if (activeView === 'playground') return <CodePlayground />;

    switch (currentPersona) {
      case 'STUDENT':
        if (activeView === 'materials') return <StudentTools />;
        return <StudentDashboard />;
      case 'TEACHER':
        if (activeView === 'create') return <TeacherDashboard />; // Reusing for simplicity, normally separate
        return <TeacherDashboard />;
      case 'INSTITUTION':
        return <InstitutionDashboard />;
      default:
        return <div>Select a persona</div>;
    }
  };

  const handlePersonaSwitch = (p: Persona) => {
      setCurrentPersona(p);
      setActiveView('dashboard');
  };

  return (
    <div className="min-h-screen bg-background text-text">
       <Layout 
         currentPersona={currentPersona} 
         onSwitchPersona={handlePersonaSwitch}
         lang={lang}
         setLang={setLang}
         currentView={activeView}
         onNavigate={setActiveView}
        >
           {renderContent()}
       </Layout>
    </div>
  );
};

