import { GoogleGenAI, Type } from "@google/genai";

const getAI = () => {
    const apiKey = process.env.API_KEY; 
    if (!apiKey) {
        console.warn("API_KEY is missing from environment variables.");
    }
    return new GoogleGenAI({ apiKey: apiKey || 'dummy-key-to-prevent-crash' });
};

// Helper to safely parse JSON from AI response
const safeJSONParse = (text: string, fallback: any) => {
    try {
        // Remove markdown code blocks if present
        const cleaned = text.replace(/```json/g, '').replace(/```/g, '').trim();
        return JSON.parse(cleaned);
    } catch (e) {
        console.error("JSON Parse Error:", e);
        return fallback;
    }
};

export const GeminiService = {
  summarize: async (text: string): Promise<string> => {
    try {
        const ai = getAI();
        const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: `Summarize the following text concisely for a student study aid:\n\n${text}`,
        });
        return response.text || "Could not generate summary.";
    } catch (e) {
        console.error("Gemini Summarize Error:", e);
        throw new Error("Failed to generate summary. Please check your connection.");
    }
  },

  generateFlashcards: async (content: string): Promise<any[]> => {
    try {
        const ai = getAI();
        const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: `Create 5 study flashcards from the following content. Return valid JSON.`,
        config: {
            responseMimeType: 'application/json',
            responseSchema: {
            type: Type.ARRAY,
            items: {
                type: Type.OBJECT,
                properties: {
                front: { type: Type.STRING },
                back: { type: Type.STRING },
                },
                required: ['front', 'back']
            },
            },
        },
        });
        return safeJSONParse(response.text || '[]', []);
    } catch (e) {
        console.error("Gemini Flashcard Error:", e);
        throw new Error("Failed to generate flashcards.");
    }
  },

  generateQA: async (content: string): Promise<any> => {
    try {
        const ai = getAI();
        const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: `Generate a Q&A set from this content. Include 2 Multiple Choice, 2 Short Answer, and 1 Long Answer questions.`,
        config: {
            responseMimeType: 'application/json',
            responseSchema: {
                type: Type.OBJECT,
                properties: {
                    mcq: { 
                        type: Type.ARRAY, 
                        items: { 
                            type: Type.OBJECT,
                            properties: {
                                question: { type: Type.STRING },
                                options: { type: Type.ARRAY, items: { type: Type.STRING }},
                                correctAnswer: { type: Type.STRING }
                            }
                        }
                    },
                    shortAnswer: {
                        type: Type.ARRAY,
                        items: {
                            type: Type.OBJECT,
                            properties: {
                                question: { type: Type.STRING },
                                answer: { type: Type.STRING }
                            }
                        }
                    },
                    longAnswer: {
                        type: Type.ARRAY,
                        items: {
                            type: Type.OBJECT,
                            properties: {
                                question: { type: Type.STRING },
                                answer: { type: Type.STRING }
                            }
                        }
                    }
                }
            }
        }
        });
        return safeJSONParse(response.text || '{}', {});
    } catch (e) {
         console.error("Gemini QA Error:", e);
         throw new Error("Failed to generate Q&A.");
    }
  },

  generateMindMap: async (content: string): Promise<string> => {
    try {
        const ai = getAI();
        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash',
            contents: `Generate a Mermaid.js mindmap based on the text below.

            STRICT RULES:
            1. Start strictly with "mindmap".
            2. Use indentation (2 or 4 spaces) to define hierarchy.
            3. Do NOT use brackets () [] {} inside node text unless they are wrapped in quotes.
            4. Keep node text short (2-5 words max).
            5. Do not output markdown code fences (no \`\`\`).
            6. Return ONLY the mermaid code.

            Text to visualize:
            ${content}`
        });
        let text = response.text || '';
        // Aggressive cleanup to ensure clean syntax
        text = text.replace(/^```(mermaid)?/gm, '').replace(/```$/gm, '').trim();
        return text;
    } catch (e) {
         console.error("Gemini Mindmap Error:", e);
         throw new Error("Failed to generate Mind Map.");
    }
  },

  runCode: async (code: string, language: string): Promise<string> => {
     try {
        const ai = getAI();
        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash',
            contents: `Act as a code execution engine. Simulate the output of the following ${language} code. 
            If there is an error, describe it. Only provide the output, no conversational filler.

            Code:
            ${code}`
        });
        return response.text || "No output.";
     } catch (e) {
         console.error("Gemini Code Run Error:", e);
         return "Error executing code via AI simulation.";
     }
  },

  generatePaper: async (topic: string, grade: string): Promise<any> => {
     try {
        const ai = getAI();
        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash',
            contents: `Create a question paper for Grade ${grade} on the topic: ${topic}.`,
            config: {
                responseMimeType: 'application/json',
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        title: { type: Type.STRING },
                        duration: { type: Type.STRING },
                        sections: {
                            type: Type.ARRAY,
                            items: {
                                type: Type.OBJECT,
                                properties: {
                                    name: { type: Type.STRING },
                                    questions: { 
                                        type: Type.ARRAY,
                                        items: { type: Type.STRING }
                                    }
                                }
                            }
                        }
                    }
                }
            }
        });
        return safeJSONParse(response.text || '{}', null);
     } catch (e) {
         console.error("Gemini Paper Gen Error:", e);
         throw new Error("Failed to generate question paper.");
     }
  },

  getImprovementAreas: async (): Promise<any[]> => {
      try {
        const ai = getAI();
        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash',
            contents: "Analyze a hypothetical student's recent poor performance in Calculus (Derivatives) and Physics (Kinematics). Suggest 3 specific areas for improvement.",
            config: {
                responseMimeType: 'application/json',
                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            topic: { type: Type.STRING },
                            suggestion: { type: Type.STRING },
                            priority: { type: Type.STRING }
                        }
                    }
                }
            }
        });
        return safeJSONParse(response.text || '[]', []);
      } catch (e) {
          console.error("Gemini Improvement Areas Error:", e);
          return []; // Return empty array gracefully on dashboard load failure
      }
  }
};

