export const StudentTools: React.FC<StudentViewProps> = ({ lang }) => {
    const [inputText, setInputText] = useState('');
    const [result, setResult] = useState<any>(null);
    const [loading, setLoading] = useState(false);
    const [activeTool, setActiveTool] = useState<'SUMMARY' | 'FLASHCARD' | 'MINDMAP' | 'QA'>('SUMMARY');
    const [history, setHistory] = useState<HistoryItem[]>([]);
    const { addToast } = useToast();
    const t = translations[lang] || translations['en'];

    useEffect(() => {
        setHistory(StorageService.getHistory('STUDENT').filter(h => h.type === activeTool));
    }, [activeTool]);

    const handleGenerate = async () => {
        if (!inputText) {
            addToast(t.pleaseEnterText, "error");
            return;
        }
        setLoading(true);
        setResult(null);

        try {
            let res;
            if (activeTool === 'SUMMARY') res = await GeminiService.summarize(inputText);
            if (activeTool === 'FLASHCARD') res = await GeminiService.generateFlashcards(inputText);
            if (activeTool === 'QA') res = await GeminiService.generateQA(inputText);
            if (activeTool === 'MINDMAP') res = await GeminiService.generateMindMap(inputText);

            setResult(res);
            addToast(t.generatedSuccess, "success");

            const newItem: HistoryItem = {
                id: Date.now().toString(),
                type: activeTool,
                title: inputText.substring(0, 30) + '...',
                content: res,
                createdAt: Date.now()
            };
            StorageService.addHistoryItem('STUDENT', newItem);
            setHistory(prev => [newItem, ...prev]);
        } catch (e: any) {
            console.error(e);
            addToast(e.message || "Something went wrong", "error");
        } finally {
            setLoading(false);
        }
    };

    const handleDeleteHistory = (id: string) => {
        StorageService.deleteHistoryItem('STUDENT', id);
        setHistory(prev => prev.filter(h => h.id !== id));
        addToast("Item deleted", "info");
    };

    const renderResult = (data: any) => {
        if (!data) return null;
        if (activeTool === 'SUMMARY') return <p className="leading-relaxed text-text/90">{data}</p>;
        if (activeTool === 'FLASHCARD') return (
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                {(data as any[]).map((card, i) => (
                    <div key={i} className="group h-40 perspective cursor-pointer">
                        <div className="relative w-full h-full duration-500 preserve-3d group-hover:rotate-y-180">
                            <div className="absolute inset-0 backface-hidden bg-surface border border-border p-4 rounded-xl flex items-center justify-center text-center">
                                <p className="font-medium text-text">{card.front}</p>
                            </div>
                            <div className="absolute inset-0 rotate-y-180 backface-hidden bg-primary/20 border border-primary/50 p-4 rounded-xl flex items-center justify-center text-center">
                                <p className="text-white">{card.back}</p>
                            </div>
                        </div>
                    </div>
                ))}
            </div>
        );
        if (activeTool === 'MINDMAP') {
             return <MermaidChart chart={data} />;
        }
        if (activeTool === 'QA') {
            const qa = data;
            return (
                <div className="space-y-6">
                    {qa.mcq && qa.mcq.map((q: any, i: number) => (
                        <div key={`mcq-${i}`} className="p-4 bg-background rounded-lg border border-border">
                            <Badge variant="info">MCQ</Badge>
                            <p className="mt-2 font-medium text-text">{q.question}</p>
                            <div className="mt-2 space-y-1 pl-4">
                                {q.options.map((opt: string, idx: number) => (
                                    <div key={idx} className={`text-sm ${opt === q.correctAnswer ? 'text-green-500 font-bold' : 'text-muted'}`}>
                                        {String.fromCharCode(65+idx)}. {opt}
                                    </div>
                                ))}
                            </div>
                        </div>
                    ))}
                     {qa.shortAnswer && qa.shortAnswer.map((q: any, i: number) => (
                        <div key={`sa-${i}`} className="p-4 bg-background rounded-lg border border-border">
                            <Badge variant="warning">Short Answer</Badge>
                             <p className="mt-2 font-medium text-text">{q.question}</p>
                             <p className="mt-1 text-sm text-muted italic">Ans: {q.answer}</p>
                        </div>
                    ))}
                </div>
            )
        }
        return null;
    };

    const toolKeys = ['SUMMARY', 'FLASHCARD', 'QA', 'MINDMAP'];
    const toolLabels: Record<string, string> = {
        'SUMMARY': t.summarize,
        'FLASHCARD': t.flashcards,
        'QA': t.qa,
        'MINDMAP': t.mindMap
    };

    return (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 h-[calc(100vh-100px)]">
            <div className="lg:col-span-2 space-y-6 overflow-y-auto pr-2">
                <Card title={t.aiTools}>
                    <div className="flex gap-2 mb-6 border-b border-border pb-4 overflow-x-auto">
                        {toolKeys.map((k) => (
                            <button 
                                key={k}
                                onClick={() => { setActiveTool(k as any); setResult(null); }}
                                className={`px-4 py-2 rounded-full text-sm font-medium transition-colors whitespace-nowrap ${activeTool === k ? 'bg-primary text-white' : 'bg-surface text-muted hover:text-white'}`}
                            >
                                {toolLabels[k]}
                            </button>
                        ))}
