        StorageService.getAllMaterials().then(setMaterials);
    }, []);

    const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
             // Reset selected material when file is uploaded
             setSelectedMaterialId('');
             const reader = new FileReader();
             reader.onload = (evt) => {
                 const result = evt.target?.result as string;
                 // result is data:mime;base64,data...
                 const match = result.match(/^data:(.*);base64,(.*)$/);
                 if (match) {
                     setUploadedFile({
                         name: file.name,
                         mimeType: match[1],
                         data: match[2]
                     });
                 }
             };
             reader.readAsDataURL(file);
        }
    };

    const handleSaveMaterial = async () => {
        if (!uploadedFile) return;
        const newMaterial: Material = {
            id: Date.now().toString(),
            title: uploadedFile.name,
            type: uploadedFile.mimeType.includes('pdf') ? 'PDF' : uploadedFile.mimeType.includes('image') ? 'IMAGE' : 'TEXT',
            content: `data:${uploadedFile.mimeType};base64,${uploadedFile.data}`,
            createdAt: Date.now()
        };
        await StorageService.saveMaterial(newMaterial);
        setMaterials(prev => [newMaterial, ...prev]);
        addToast("Material saved successfully", "success");
    };

    const handleGenerate = async () => {
        if (!inputText && !uploadedFile && !selectedMaterialId) {
            addToast("Please enter text or select a file/material.", "error");
            return;
        }
        setLoading(true);
        setResult(null);

        try {
            // Prepare File Data
            let fileData: FileData | undefined = undefined;
            if (uploadedFile) {
                fileData = { mimeType: uploadedFile.mimeType, data: uploadedFile.data };
            } else if (selectedMaterialId) {
                const mat = materials.find(m => m.id === selectedMaterialId);
                if (mat) {
                    const match = mat.content.match(/^data:(.*);base64,(.*)$/);
                    if (match) {
                        fileData = { mimeType: match[1], data: match[2] };
                    } else if (mat.type === 'TEXT') {
                        // If it's pure text content, append to prompt, though we primarily handle DataURLs here
                    }
                }
            }

            let res;
            if (activeTool === 'SUMMARY') res = await GeminiService.summarize(inputText, fileData);
            if (activeTool === 'FLASHCARD') res = await GeminiService.generateFlashcards(inputText, fileData);
            if (activeTool === 'QA') res = await GeminiService.generateQA(inputText, fileData);
            if (activeTool === 'MINDMAP') res = await GeminiService.generateMindMap(inputText, fileData);

            setResult(res);
            addToast(t.generatedSuccess, "success");

            const newItem: HistoryItem = {
                id: Date.now().toString(),
                type: activeTool,
                title: (uploadedFile?.name || (selectedMaterialId ? materials.find(m=>m.id===selectedMaterialId)?.title : inputText.substring(0, 20))) + '...',
                content: res,
                createdAt: Date.now()
            };
            StorageService.addHistoryItem('STUDENT', newItem);
            setHistory(prev => [newItem, ...prev]);
        } catch (e: any) {
            console.error(e);
            addToast(e.message || "Something went wrong", "error");
        } finally {
            setLoading(false);
        }
    };

    const handleDeleteHistory = (id: string) => {
        StorageService.deleteHistoryItem('STUDENT', id);
        setHistory(prev => prev.filter(h => h.id !== id));
        addToast("Item deleted", "info");
    };

    const renderResult = (data: any) => {
        if (!data) return null;
        if (activeTool === 'SUMMARY') return <p className="leading-relaxed text-text/90 whitespace-pre-wrap">{data}</p>;
        if (activeTool === 'FLASHCARD') return (
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                {(data as any[]).map((card, i) => (
                    <div key={i} className="group h-40 perspective cursor-pointer">
                        <div className="relative w-full h-full duration-500 preserve-3d group-hover:rotate-y-180">
                            <div className="absolute inset-0 backface-hidden bg-surface border border-border p-4 rounded-xl flex items-center justify-center text-center shadow-md">
                                <p className="font-medium text-text">{card.front}</p>
                            </div>
                            <div className="absolute inset-0 rotate-y-180 backface-hidden bg-primary/20 border border-primary/50 p-4 rounded-xl flex items-center justify-center text-center shadow-md">
                                <p className="text-text font-medium">{card.back}</p>
                            </div>
                        </div>
                    </div>
                ))}
            </div>
        );
        if (activeTool === 'MINDMAP') {
             return <MermaidChart chart={data} />;
        }
        if (activeTool === 'QA') {
            const qa = data;
            return (
                <div className="space-y-6">
                    {qa.mcq && qa.mcq.map((q: any, i: number) => (
                        <div key={`mcq-${i}`} className="p-4 bg-background rounded-lg border border-border">
                            <Badge variant="info">MCQ</Badge>
                            <p className="mt-2 font-medium text-text">{q.question}</p>
                            <div className="mt-2 space-y-1 pl-4">
                                {q.options.map((opt: string, idx: number) => (
                                    <div key={idx} className={`text-sm ${opt === q.correctAnswer ? 'text-green-500 font-bold' : 'text-muted'}`}>
                                        {String.fromCharCode(65+idx)}. {opt}
                                    </div>
                                ))}
                            </div>
                        </div>
                    ))}
                     {qa.shortAnswer && qa.shortAnswer.map((q: any, i: number) => (
                        <div key={`sa-${i}`} className="p-4 bg-background rounded-lg border border-border">
                            <Badge variant="warning">Short Answer</Badge>
                             <p className="mt-2 font-medium text-text">{q.question}</p>
                             <p className="mt-1 text-sm text-muted italic">Ans: {q.answer}</p>
                        </div>
                    ))}
                </div>
            )
        }
        return null;
    };

    const toolKeys = ['SUMMARY', 'FLASHCARD', 'QA', 'MINDMAP'];
    const toolLabels: Record<string, string> = {
        'SUMMARY': t.summarize,
        'FLASHCARD': t.flashcards,
        'QA': t.qa,
        'MINDMAP': t.mindMap
    };

    return (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 h-[calc(100vh-100px)]">
            <div className="lg:col-span-2 space-y-6 overflow-y-auto pr-2">
                <Card title={t.aiTools}>
                    <div className="flex gap-2 mb-6 border-b border-border pb-4 overflow-x-auto">
                        {toolKeys.map((k) => (
                            <button 
                                key={k}
                                onClick={() => { setActiveTool(k as any); setResult(null); }}
                                className={`px-4 py-2 rounded-full text-sm font-medium transition-colors whitespace-nowrap ${activeTool === k ? 'bg-primary text-white' : 'bg-surface text-muted hover:text-text hover:bg-black/5 dark:hover:bg-white/5'}`}
                            >
                                {toolLabels[k]}
                            </button>
                        ))}
                    </div>

                    <div className="space-y-4">
                        {/* Source Selection Area */}
                        <div className="p-4 bg-background border border-border rounded-lg space-y-3">
                            <div className="flex items-center justify-between">
                                <span className="text-sm font-medium text-muted">Input Source</span>
                                {(uploadedFile || selectedMaterialId) && (
                                    <Badge variant="success">Source Active</Badge>
                                )}
                            </div>

                            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                                <div className="space-y-2">
                                     <div className="relative">
                                         <input 
                                             type="file" 
                                             ref={fileInputRef}
                                             onChange={handleFileUpload}
                                             className="hidden"
                                             accept="image/*,application/pdf"
                                         />
                                         <Button 
                                             variant="secondary" 
                                             size="sm" 
                                             className="w-full text-xs" 
                                             onClick={() => fileInputRef.current?.click()}
                                         >
                                             <Upload className="w-3 h-3 mr-2" /> Upload File (PDF/Image)
                                         </Button>
                                     </div>
                                </div>

                                <div className="space-y-2">
                                     <Select 
                                         value={selectedMaterialId} 
                                         onChange={(e) => { 
                                             setSelectedMaterialId(e.target.value); 
                                             if (e.target.value) setUploadedFile(null); // Clear manual upload if saved selected
                                         }}
                                         className="text-xs py-1.5 h-8"
                                     >
                                         <option value="">Select Saved Material</option>
                                         {materials.map(m => (
                                             <option key={m.id} value={m.id}>{m.title}</option>
                                         ))}
                                     </Select>
                                </div>
                            </div>

                            {/* Active File Indicator */}
                            {uploadedFile && (
                                <div className="flex items-center justify-between p-2 bg-primary/10 rounded border border-primary/20">
                                    <div className="flex items-center gap-2 overflow-hidden">
                                        <FileIcon className="w-4 h-4 text-primary shrink-0" />
                                        <span className="text-xs text-text truncate">{uploadedFile.name}</span>
                                    </div>
                                    <div className="flex items-center gap-2">
                                         <button onClick={handleSaveMaterial} className="text-primary hover:text-primary-hover" title="Save to Materials">
                                             <Save className="w-4 h-4" />
                                         </button>
                                         <button onClick={() => { setUploadedFile(null); if (fileInputRef.current) fileInputRef.current.value = ''; }} className="text-muted hover:text-red-500">
                                             <X className="w-4 h-4" />
                                         </button>
                                    </div>
                                </div>
                            )}
                        </div>

                        <Textarea 
                            rows={4} 
                            placeholder={`${t.pasteText} or describe the file...`} 
                            value={inputText}
                            onChange={(e) => setInputText(e.target.value)}
                        />
                        <div className="flex justify-end">
                            <Button onClick={handleGenerate} loading={loading}>
                                <Zap className="w-4 h-4 mr-2" />
                                {t.generate}
                            </Button>
                        </div>
                    </div>
                </Card>

                {result && (
                    <Card title={t.result} className="border-primary/50">
                        {renderResult(result)}
                    </Card>
                )}
            </div>

            <div className="space-y-4 overflow-y-auto h-full pl-2">
                <div className="flex items-center justify-between mb-2">
                    <h3 className="font-semibold text-lg text-text">{t.history}</h3>
                    <span className="text-xs text-muted">{history.length} {t.items}</span>
                </div>
                {history.map((item) => (
                    <div key={item.id} className="bg-surface border border-border rounded-lg p-3 group">
                        <div className="flex justify-between items-start mb-2">
                            <h4 className="text-sm font-medium line-clamp-1 text-text">{item.title}</h4>
                            <button onClick={() => handleDeleteHistory(item.id)} className="text-muted hover:text-red-500 opacity-0 group-hover:opacity-100 transition-opacity">
                                <Trash2 className="w-4 h-4" />
                            </button>
                        </div>
                        <div className="flex justify-between items-center">
                            <span className="text-xs text-muted">{new Date(item.createdAt).toLocaleDateString()}</span>
                            <Button 
                                variant="secondary" 
                                size="sm" 
                                className="h-6 text-xs px-2"
                                onClick={() => setResult(item.content)}
                            >
                                {t.view}
                            </Button>
                        </div>
                    </div>
                ))}
            </div>
        </div>
    );
};

import { GoogleGenAI, Type } from "@google/genai";

const getAI = () => {
    const apiKey = process.env.API_KEY; 
    if (!apiKey) {
        console.warn("API_KEY is missing from environment variables.");
    }
    return new GoogleGenAI({ apiKey: apiKey || 'dummy-key-to-prevent-crash' });
};

// Helper to safely parse JSON from AI response
const safeJSONParse = (text: string, fallback: any) => {
    try {
        // Remove markdown code blocks if present
        const cleaned = text.replace(/```json/g, '').replace(/```/g, '').trim();
        return JSON.parse(cleaned);
    } catch (e) {
        console.error("JSON Parse Error:", e);
        return fallback;
    }
};

export interface FileData {
    mimeType: string;
    data: string; // Base64 encoded string
}

export const GeminiService = {
  summarize: async (text: string, file?: FileData): Promise<string> => {
    try {
        const ai = getAI();
        const parts: any[] = [];
        if (file) {
            parts.push({ inlineData: { mimeType: file.mimeType, data: file.data } });
        }
        parts.push({ text: `Summarize the following content concisely for a student study aid.\n\nAdditional Context/Prompt: ${text}` });

        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash',
            contents: { parts },
        });
        return response.text || "Could not generate summary.";
    } catch (e) {
        console.error("Gemini Summarize Error:", e);
        throw new Error("Failed to generate summary. Please check your connection.");
    }
  },

  generateFlashcards: async (content: string, file?: FileData): Promise<any[]> => {
    try {
        const ai = getAI();
        const parts: any[] = [];
        if (file) {
            parts.push({ inlineData: { mimeType: file.mimeType, data: file.data } });
        }
        parts.push({ text: `Create 5 study flashcards from the provided content. Return valid JSON.\n\nContext: ${content}` });

        const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: { parts },
        config: {
            responseMimeType: 'application/json',
            responseSchema: {
            type: Type.ARRAY,
            items: {
                type: Type.OBJECT,
                properties: {
                front: { type: Type.STRING },
                back: { type: Type.STRING },
                },
                required: ['front', 'back']
            },
            },
        },
        });
        return safeJSONParse(response.text || '[]', []);
    } catch (e) {
        console.error("Gemini Flashcard Error:", e);
        throw new Error("Failed to generate flashcards.");
    }
  },

  generateQA: async (content: string, file?: FileData): Promise<any> => {
    try {
        const ai = getAI();
        const parts: any[] = [];
        if (file) {
            parts.push({ inlineData: { mimeType: file.mimeType, data: file.data } });
        }
        parts.push({ text: `Generate a comprehensive Question & Answer set from this content strictly following this structure:
        1. 10 Multiple Choice Questions (MCQs).
        2. 10 Short Answer Questions (2 Marks each).
        3. 10 Medium Answer Questions (5 Marks each).
        4. 10 Long Answer Questions (10 Marks each).
        5. 5 Very Long Answer Questions (15 Marks each).

        Ensure the questions cover the uploaded material thoroughly.

        Context: ${content}` });

        const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: { parts },
        config: {
            responseMimeType: 'application/json',
            responseSchema: {
                type: Type.OBJECT,
                properties: {
                    mcq: { 
                        type: Type.ARRAY, 
                        items: { 
                            type: Type.OBJECT,
                            properties: {
                                question: { type: Type.STRING },
                                options: { type: Type.ARRAY, items: { type: Type.STRING }},
                                correctAnswer: { type: Type.STRING }
                            }
                        }
                    },
                    questions2Marks: {
                        type: Type.ARRAY,
                        items: {
                            type: Type.OBJECT,
                            properties: {
                                question: { type: Type.STRING },
                                answer: { type: Type.STRING }
                            }
                        }
                    },
                    questions5Marks: {
                        type: Type.ARRAY,
                        items: {
                            type: Type.OBJECT,
                            properties: {
                                question: { type: Type.STRING },
                                answer: { type: Type.STRING }
                            }
                        }
                    },
                    questions10Marks: {
                        type: Type.ARRAY,
                        items: {
                            type: Type.OBJECT,
                            properties: {
                                question: { type: Type.STRING },
                                answer: { type: Type.STRING }
                            }
                        }
                    },
                    questions15Marks: {
                        type: Type.ARRAY,
                        items: {
                            type: Type.OBJECT,
                            properties: {
                                question: { type: Type.STRING },
                                answer: { type: Type.STRING }
                            }
                        }
                    }
                }
            }
        }
        });
        return safeJSONParse(response.text || '{}', {});
    } catch (e) {
         console.error("Gemini QA Error:", e);
         throw new Error("Failed to generate Q&A.");
    }
  },

  generateMindMap: async (content: string, file?: FileData): Promise<string> => {
    try {
        const ai = getAI();
        const parts: any[] = [];
        if (file) {
            parts.push({ inlineData: { mimeType: file.mimeType, data: file.data } });
        }
        parts.push({ text: `Generate a Mermaid.js mindmap based on the content below.

            STRICT RULES:
            1. Start strictly with "mindmap".
            2. Use indentation (2 or 4 spaces) to define hierarchy.
            3. Do NOT use brackets () [] {} inside node text unless they are wrapped in quotes.
            4. Keep node text short (2-5 words max).
            5. Do not output markdown code fences (no \`\`\`).
            6. Return ONLY the mermaid code.

            Context:
            ${content}` });

        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash',
            contents: { parts }
        });
        let text = response.text || '';
        // Aggressive cleanup to ensure clean syntax
        text = text.replace(/^```(mermaid)?/gm, '').replace(/```$/gm, '').trim();
        return text;
    } catch (e) {
         console.error("Gemini Mindmap Error:", e);
         throw new Error("Failed to generate Mind Map.");
    }
  },

  runCode: async (code: string, language: string): Promise<string> => {
     try {
        const ai = getAI();
        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash',
            contents: `Act as a code execution engine. Simulate the output of the following ${language} code. 
            If there is an error, describe it. Only provide the output, no conversational filler.

            Code:
            ${code}`
        });
        return response.text || "No output.";
     } catch (e) {
         console.error("Gemini Code Run Error:", e);
         return "Error executing code via AI simulation.";
     }
  },

  generatePaper: async (topic: string, grade: string, file?: FileData): Promise<any> => {
     try {
        const ai = getAI();
        const parts: any[] = [];
        if (file) {
             parts.push({ inlineData: { mimeType: file.mimeType, data: file.data } });
        }
        parts.push({ text: `Create a question paper for Grade ${grade} on the topic: ${topic}.` });

        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash',
            contents: { parts },
            config: {
                responseMimeType: 'application/json',
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        title: { type: Type.STRING },
                        duration: { type: Type.STRING },
                        sections: {
                            type: Type.ARRAY,
                            items: {
                                type: Type.OBJECT,
                                properties: {
                                    name: { type: Type.STRING },
                                    questions: { 
                                        type: Type.ARRAY,
                                        items: { type: Type.STRING }
                                    }
                                }
                            }
                        }
                    }
                }
            }
        });
        return safeJSONParse(response.text || '{}', null);
     } catch (e) {
         console.error("Gemini Paper Gen Error:", e);
         throw new Error("Failed to generate question paper.");
     }
  },

  getImprovementAreas: async (): Promise<any[]> => {
      try {
        const ai = getAI();
        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash',
            contents: "Analyze a hypothetical student's recent poor performance in Calculus (Derivatives) and Physics (Kinematics). Suggest 3 specific areas for improvement.",
            config: {
                responseMimeType: 'application/json',
                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            topic: { type: Type.STRING },
                            suggestion: { type: Type.STRING },
                            priority: { type: Type.STRING }
                        }
                    }
                }
            }
        });
        return safeJSONParse(response.text || '[]', []);
      } catch (e) {
          console.error("Gemini Improvement Areas Error:", e);
          return []; // Return empty array gracefully on dashboard load failure
      }
  }
};

