import React, { useState, useEffect, createContext, useContext } from 'react';
import Layout from './components/Layout';
import LandingPage from './components/LandingPage';
import { Persona } from './types';
import { StudentDashboard, StudentTools, StudentExams } from './views/Student';
import CodePlayground from './components/CodePlayground';
import { ToastContainer, Card } from './components/ui/Components';
import { translations } from './utils/translations';
import { Briefcase, MessageSquare } from 'lucide-react';

// Toast Context
interface Toast {
    id: string;
    message: string;
    type: 'success' | 'error' | 'info';
}
const ToastContext = createContext<{ addToast: (msg: string, type: 'success' | 'error' | 'info') => void }>({ addToast: () => {} });
export const useToast = () => useContext(ToastContext);

const App: React.FC = () => {
  const [hasCompletedOnboarding, setHasCompletedOnboarding] = useState(false);
  const [currentPersona, setCurrentPersona] = useState<Persona>('STUDENT');
  const [activeView, setActiveView] = useState('dashboard');
  const [lang, setLang] = useState('en');
  const [theme, setTheme] = useState<'light' | 'dark'>('dark');
  const [toasts, setToasts] = useState<Toast[]>([]);

  // Theme Effect
  useEffect(() => {
    if (theme === 'dark') {
        document.documentElement.classList.add('dark');
        document.documentElement.style.setProperty('color-scheme', 'dark');
    } else {
        document.documentElement.classList.remove('dark');
        document.documentElement.style.setProperty('color-scheme', 'light');
    }
  }, [theme]);

  // Toast Function
  const addToast = (message: string, type: 'success' | 'error' | 'info') => {
      const id = Date.now().toString();
      setToasts(prev => [...prev, { id, message, type }]);
      setTimeout(() => setToasts(prev => prev.filter(t => t.id !== id)), 5000);
  };

  const handleOnboardingComplete = (selectedLang: string) => {
      setLang(selectedLang);
      setHasCompletedOnboarding(true);
  };

  const renderContent = () => {
    if (activeView === 'playground') return <CodePlayground lang={lang} />;

    switch (currentPersona) {
      case 'STUDENT':
        if (activeView === 'materials') return <StudentTools lang={lang} onNavigate={setActiveView} />;
        if (activeView === 'exams') return <StudentExams lang={lang} />;
        return <StudentDashboard lang={lang} theme={theme} onNavigate={setActiveView} />;
      case 'PROFESSIONAL':
        return (
            <div className="flex flex-col items-center justify-center min-h-[60vh] text-center space-y-6 animate-in fade-in duration-500">
                <div className="p-6 bg-secondary/10 rounded-full">
                    <Briefcase className="w-16 h-16 text-secondary" />
                </div>
                <div className="space-y-2 max-w-md">
                    <h2 className="text-3xl font-bold text-text">Working Professional Profile</h2>
                    <p className="text-muted text-lg">This profile is currently under construction. Check back soon for advanced career tools and networking features.</p>
                </div>
                <Card className="w-full max-w-sm mx-auto p-4 opacity-75 border-dashed">
                     <p className="text-sm text-muted italic">Planned Features: Resume Builder, Skill Gap Analysis, Interview Prep AI</p>
                </Card>
            </div>
        );
      case 'INTERVIEW_PREP':
        return (
            <div className="flex flex-col items-center justify-center min-h-[60vh] text-center space-y-6 animate-in fade-in duration-500">
                <div className="p-6 bg-purple-500/10 rounded-full">
                    <MessageSquare className="w-16 h-16 text-purple-500" />
                </div>
                <div className="space-y-2 max-w-md">
                    <h2 className="text-3xl font-bold text-text">Interview Preparation</h2>
                    <p className="text-muted text-lg">Master your upcoming interviews. This module is coming soon.</p>
                </div>
                 <Card className="w-full max-w-sm mx-auto p-4 opacity-75 border-dashed">
                     <p className="text-sm text-muted italic">Planned Features: AI Mock Interviews, STAR Method Practice, Resume Scoring</p>
                </Card>
            </div>
        );
      default:
        return <div>{translations[lang]?.selectPersona || "Select a persona"}</div>;
    }
  };

  const handlePersonaSwitch = (p: Persona) => {
      setCurrentPersona(p);
      setActiveView('dashboard');
      const name = p === 'STUDENT' ? 'Student' : p === 'PROFESSIONAL' ? 'Professional' : 'Interview Prep';
      addToast(`Switched to ${name} view`, 'info');
  };

  // Reset to landing page
  const handleLogoClick = () => {
      setHasCompletedOnboarding(false);
  };

  if (!hasCompletedOnboarding) {
      return <LandingPage onComplete={handleOnboardingComplete} theme={theme} />;
  }

  return (
    <ToastContext.Provider value={{ addToast }}>
        <div className="min-h-screen bg-background text-text">
        <Layout 
            currentPersona={currentPersona} 
            onSwitchPersona={handlePersonaSwitch}
            lang={lang}
            setLang={setLang}
            theme={theme}
            toggleTheme={() => setTheme(prev => prev === 'dark' ? 'light' : 'dark')}
            currentView={activeView}
            onNavigate={setActiveView}
            onLogoClick={handleLogoClick}
            >
            {renderContent()}
        </Layout>
        <ToastContainer toasts={toasts} />
        </div>
    </ToastContext.Provider>
  );
};

export default App;

