  currentPersona: Persona;
  onSwitchPersona: (p: Persona) => void;
  lang: string;
  setLang: (l: string) => void;
  theme: 'light' | 'dark';
  toggleTheme: () => void;
  currentView: string;
  onNavigate: (view: string) => void;
