// --- SUB-COMPONENTS FOR FEATURES ---

const DocumentIntelligence: React.FC<{ lang: string }> = ({ lang }) => {
    const t = translations[lang] || translations['en'];
    const [mode, setMode] = useState<'EXEC' | 'ACTION' | 'ELI5'>('EXEC');
    const [inputText, setInputText] = useState('');
    const [result, setResult] = useState('');
    const [loading, setLoading] = useState(false);
    const [uploadedFile, setUploadedFile] = useState<{name: string, data: string, mimeType: string} | null>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);
    const { addToast } = useToast();

    const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
             const reader = new FileReader();
             reader.onload = (evt) => {
                 const res = evt.target?.result as string;
                 const match = res.match(/^data:(.*);base64,(.*)$/);
                 if (match) {
                     setUploadedFile({ name: file.name, mimeType: match[1], data: match[2] });
                 }
             };
             reader.readAsDataURL(file);
        }
    };

    const handleGenerate = async () => {
        if (!inputText && !uploadedFile) {
            addToast("Please provide text or a file.", "error");
            return;
        }
        setLoading(true);
        try {
            const fileData = uploadedFile ? { mimeType: uploadedFile.mimeType, data: uploadedFile.data } : undefined;
            const res = await GeminiService.corporateSummarize(inputText, fileData, mode);
            setResult(res);
        } catch (e) {
            addToast("Analysis failed", "error");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
            <div className="space-y-4">
                <Card className="space-y-4">
                     <div className="flex gap-2 mb-2">
                        {['EXEC', 'ACTION', 'ELI5'].map((m) => (
                            <button 
                                key={m}
                                onClick={() => { setMode(m as any); setResult(''); }}
                                className={`px-4 py-2 rounded-lg text-xs font-bold transition-all ${mode === m ? 'bg-secondary text-black' : 'bg-surface border border-border text-muted hover:text-text'}`}
                            >
                                {m === 'EXEC' ? t.execSummary || 'Executive Brief' : m === 'ACTION' ? t.actionItems || 'Action Items' : t.eli5 || 'ELI5'}
                            </button>
                        ))}
                    </div>

                    <div className="p-4 bg-background border border-border rounded-lg space-y-3">
                         <div className="relative">
                             <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" accept=".pdf,.txt,.docx" />
                             <Button variant="secondary" size="sm" className="w-full text-xs" onClick={() => fileInputRef.current?.click()}>
                                 <Upload className="w-3 h-3 mr-2" /> Upload Document (PDF)
                             </Button>
                         </div>
                         {uploadedFile && (
                            <div className="flex items-center justify-between p-2 bg-primary/10 rounded border border-primary/20">
                                <span className="text-xs text-text truncate flex items-center gap-2"><File className="w-3 h-3"/> {uploadedFile.name}</span>
                                <button onClick={() => setUploadedFile(null)}><X className="w-3 h-3"/></button>
                            </div>
                         )}
                    </div>

                    <Textarea 
                        rows={6} 
                        placeholder="Or paste document text / transcript here..." 
                        value={inputText}
                        onChange={e => setInputText(e.target.value)}
                    />

                    <Button className="w-full" onClick={handleGenerate} loading={loading}>
                        <Zap className="w-4 h-4 mr-2" /> Analyze Document
                    </Button>
                </Card>
            </div>
            <Card className="bg-surface/50 h-full min-h-[400px]">
                <h3 className="text-sm font-semibold text-muted mb-4 uppercase tracking-wider">Analysis Result</h3>
                <div className="prose prose-invert max-w-none text-sm leading-relaxed whitespace-pre-wrap">
                    {result || <span className="text-muted italic">Result will appear here...</span>}
                </div>
            </Card>
        </div>
    );
};

