// --- COMPONENT: SIP CALCULATOR ---
const SIPCalculator: React.FC = () => {
    const [monthly, setMonthly] = useState(5000);
    const [rate, setRate] = useState(12);
    const [years, setYears] = useState(10);

    const i = rate / 100 / 12;
    const n = years * 12;
    // FV = P * [ (1+i)^n - 1 ] * (1+i) / i
    const futureValue = monthly * ((Math.pow(1 + i, n) - 1) / i) * (1 + i);
    const totalInvested = monthly * n;

    return (
        <div className="space-y-4">
            <div className="grid grid-cols-3 gap-2 text-xs">
                <div>
                    <Label>Monthly (₹)</Label>
                    <Input type="number" value={monthly} onChange={e => setMonthly(Number(e.target.value))} />
                </div>
                <div>
                    <Label>Return (%)</Label>
                    <Input type="number" value={rate} onChange={e => setRate(Number(e.target.value))} />
                </div>
                <div>
                    <Label>Years</Label>
                    <Input type="number" value={years} onChange={e => setYears(Number(e.target.value))} />
                </div>
            </div>
            <div className="p-3 bg-surface border border-border rounded-lg text-center">
                <p className="text-xs text-muted">Estimated Value</p>
                <p className="text-xl font-bold text-green-500">₹ {Math.round(futureValue).toLocaleString()}</p>
                <p className="text-xs text-muted mt-1">Invested: ₹ {totalInvested.toLocaleString()}</p>
            </div>
        </div>
    );
};

// --- COMPONENT: TAX ASSISTANT ---
const TaxAssistant: React.FC = () => {
    const [income, setIncome] = useState(800000);

    // Very simplified New Regime 2024-25 Logic
    const calculateTax = (inc: number) => {
        if (inc <= 300000) return 0;
        if (inc <= 700000) return (inc - 300000) * 0.05; // Note: Rebate usually applies up to 7L making it 0, simplified here
        if (inc <= 700000) return 0; // Effectively 0 due to 87A rebate

        // Simple slabs for demo
        // 3-7L: 5%, 7-10L: 10%, 10-12L: 15%
        let tax = 0;
        if (inc > 300000) tax += Math.min(inc - 300000, 400000) * 0.05;
        if (inc > 700000) tax += Math.min(inc - 700000, 300000) * 0.10;
        if (inc > 1000000) tax += Math.min(inc - 1000000, 200000) * 0.15;
        if (inc > 1200000) tax += (inc - 1200000) * 0.20;

        // Quick Fix for 7L rebate logic in New Regime
        if (inc <= 700000) return 0;

        return tax;
    };

    const tax = calculateTax(income);

    return (
        <div className="space-y-4">
             <div className="flex justify-between items-center">
                 <Label>Annual Income</Label>
                 <Badge variant="info">New Regime</Badge>
             </div>
             <Input type="number" value={income} onChange={e => setIncome(Number(e.target.value))} />
             <div className="p-3 bg-surface border border-border rounded-lg flex justify-between items-center">
                 <span className="text-sm font-medium">Est. Tax:</span>
                 <span className="text-lg font-bold text-red-500">₹ {tax.toLocaleString()}</span>
             </div>
             <p className="text-xs text-muted">
                 *Simplified calculation. Consult a CA for accurate filing.
             </p>
        </div>
    );
};

