// --- COMPONENT: SIP CALCULATOR ---
const SIPCalculator: React.FC = () => {
    const [monthly, setMonthly] = useState(5000);
    const [rate, setRate] = useState(12);
    const [years, setYears] = useState(10);

    const i = rate / 100 / 12;
    const n = years * 12;
    // FV = P * [ (1+i)^n - 1 ] * (1+i) / i
    const futureValue = monthly * ((Math.pow(1 + i, n) - 1) / i) * (1 + i);
    const totalInvested = monthly * n;

    return (
        <div className="space-y-4">
            <div className="grid grid-cols-3 gap-2 text-xs">
                <div>
                    <Label>Monthly (₹)</Label>
                    <Input type="number" value={monthly} onChange={e => setMonthly(Number(e.target.value))} />
                </div>
                <div>
                    <Label>Return (%)</Label>
                    <Input type="number" value={rate} onChange={e => setRate(Number(e.target.value))} />
                </div>
                <div>
                    <Label>Years</Label>
                    <Input type="number" value={years} onChange={e => setYears(Number(e.target.value))} />
                </div>
            </div>
            <div className="p-3 bg-surface border border-border rounded-lg text-center">
                <p className="text-xs text-muted">Estimated Value</p>
                <p className="text-xl font-bold text-green-500">₹ {Math.round(futureValue).toLocaleString()}</p>
                <p className="text-xs text-muted mt-1">Invested: ₹ {totalInvested.toLocaleString()}</p>
            </div>
        </div>
    );
};

