const AspirantQuiz: React.FC = () => {
    const [started, setStarted] = useState(false);
    const [loading, setLoading] = useState(false);
    const [questions, setQuestions] = useState<any[]>([]);
    const [answers, setAnswers] = useState<Record<number, string>>({});
    const [submitted, setSubmitted] = useState(false);
    const [score, setScore] = useState(0);

    const startQuiz = async () => {
        setLoading(true);
        try {
            const data = await GeminiService.generateQuizByTopic("Current Affairs & General Studies");
            setQuestions(data);
            setStarted(true);
            setSubmitted(false);
            setAnswers({});
        } catch (e) {
            console.error(e);
        } finally {
            setLoading(false);
        }
    };

    const handleSubmit = () => {
        let s = 0;
        questions.forEach((q, i) => {
            if (answers[i] === q.correctAnswer) s++;
        });
        setScore(s);
        setSubmitted(true);
    };

    if (loading) return (
        <div className="h-64 flex flex-col items-center justify-center text-muted">
             <Zap className="w-8 h-8 animate-pulse mb-2 text-primary" />
             <p>Generating Today's Quiz...</p>
        </div>
    );

    if (!started) return (
        <div className="text-center py-6">
            <Landmark className="w-12 h-12 mx-auto text-blue-600 mb-3" />
            <h3 className="text-lg font-bold">Daily General Studies Quiz</h3>
            <p className="text-sm text-muted mb-4">Test your knowledge with 5 fresh questions on Current Affairs & GS.</p>
            <Button onClick={startQuiz} className="w-full">Start Practice</Button>
        </div>
    );

    return (
        <div className="space-y-6">
             {!submitted ? (
                 <div className="space-y-6">
                     {questions.map((q, i) => (
                         <div key={i} className="pb-4 border-b border-border last:border-0">
                             <p className="font-medium text-text mb-3">{i+1}. {q.question}</p>
                             <div className="space-y-2">
                                 {q.options.map((opt: string, idx: number) => (
                                     <button
                                        key={idx}
                                        onClick={() => setAnswers(prev => ({...prev, [i]: opt}))}
                                        className={`w-full text-left p-2 rounded-lg text-sm border transition-all ${
                                            answers[i] === opt 
                                            ? 'bg-primary/20 border-primary text-primary' 
                                            : 'bg-background border-border hover:bg-surface'
                                        }`}
                                     >
                                         {opt}
                                     </button>
                                 ))}
                             </div>
                         </div>
                     ))}
                     <Button onClick={handleSubmit} className="w-full">Submit Quiz</Button>
                 </div>
             ) : (
                 <div className="text-center space-y-4">
                     <div className="p-4 bg-surface border border-border rounded-lg">
                         <h3 className="text-xl font-bold mb-1">Score: {score} / {questions.length}</h3>
                         <p className="text-sm text-muted">{score > 3 ? "Excellent Work!" : "Keep Practicing!"}</p>
                     </div>
                     <div className="text-left space-y-4 max-h-64 overflow-y-auto pr-2">
                         {questions.map((q, i) => (
                             <div key={i} className="text-sm border-b border-border pb-2">
                                 <p className="font-medium mb-1">{i+1}. {q.question}</p>
                                 <div className="flex items-center gap-2 mb-1">
                                    {answers[i] === q.correctAnswer ? <CheckCircle className="w-4 h-4 text-green-500"/> : <XCircle className="w-4 h-4 text-red-500"/>}
                                    <span className={answers[i] === q.correctAnswer ? "text-green-500" : "text-red-500"}>
                                        You: {answers[i] || 'Skipped'}
                                    </span>
                                 </div>
                                 {answers[i] !== q.correctAnswer && <p className="text-green-500">Correct: {q.correctAnswer}</p>}
                                 <p className="text-xs text-muted mt-1 bg-black/5 p-2 rounded">{q.explanation}</p>
                             </div>
                         ))}
                     </div>
                     <Button onClick={startQuiz} variant="secondary" className="w-full">Take Another Quiz</Button>
                 </div>
             )}
        </div>
    );
};

