        setLoading(true);
        try {
            const res = await GeminiService.polishEmail(intent, 'DIPLOMATIC');
            setDraft(res);
        } catch (e) {
            console.error(e);
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="space-y-4">
            <Label>What do you want to say? (Rough Note)</Label>
            <Textarea 
                placeholder="e.g., Tell client delay due to rain, will deliver tomorrow..." 
                value={intent}
                onChange={e => setIntent(e.target.value)}
            />
            <Button onClick={handleDraft} loading={loading} variant="secondary" className="w-full">
                <Send className="w-4 h-4 mr-2" /> Draft Formal Email
            </Button>
            {draft && (
                <div className="p-3 bg-surface border border-border rounded-lg text-sm whitespace-pre-wrap mt-2">
                    {draft}
                </div>
            )}
        </div>
    );
};

