  generateQA: async (content: string, file?: FileData, config?: QAConfig): Promise<any> => {
    try {
        const ai = getAI();
        const parts: any[] = [];
        if (file) {
            parts.push({ inlineData: { mimeType: file.mimeType, data: file.data } });
        }

        // Default config if not provided
        const qty = config || {
            mcq: 5,
            fillInBlanks: 5,
            short2: 5,
            short5: 3,
            long10: 2,
            long15: 1
