const CurrentAffairsFeed: React.FC = () => {
    const [news, setNews] = useState<any[]>([]);
    const [loading, setLoading] = useState(false);
    const [index, setIndex] = useState(0);

    const fetchNews = async () => {
        setLoading(true);
        const data = await GeminiService.generateCurrentAffairs();
        setNews(data);
        setIndex(0);
        setLoading(false);
    };

    useEffect(() => {
        fetchNews();
    }, []);

    const handleNext = () => setIndex(prev => (prev + 1) % news.length);
    const handlePrev = () => setIndex(prev => (prev - 1 + news.length) % news.length);

    return (
        <div className="bg-surface border border-border rounded-lg p-4 h-full flex flex-col">
            <div className="flex justify-between items-center mb-4">
                <h3 className="font-bold flex items-center gap-2">
                    <Bell className="w-4 h-4 text-orange-500" />
                    Daily Digest
                </h3>
                <Button variant="ghost" size="sm" onClick={fetchNews} disabled={loading} className="h-6 w-6 p-0 rounded-full">
                     <RefreshCw className={`w-3 h-3 ${loading ? 'animate-spin' : ''}`} />
                </Button>
            </div>

            {loading ? (
                <div className="flex-1 flex flex-col items-center justify-center space-y-3 opacity-50">
                    <div className="w-12 h-12 rounded-full border-2 border-primary border-t-transparent animate-spin"></div>
                    <p className="text-xs text-muted">Curating today's headlines...</p>
                </div>
            ) : news.length > 0 ? (
                <div className="flex-1 flex flex-col">
                    <div className="flex-1 bg-background border border-border rounded-lg p-5 relative overflow-hidden transition-all duration-300">
                        <div className="flex justify-between items-start mb-3">
                            <Badge variant={news[index].category === 'Politics' ? 'warning' : 'info'}>
                                {news[index].category}
                            </Badge>
                            <span className="text-[10px] text-muted uppercase tracking-wider">{news[index].importance} Impact</span>
                        </div>
                        <h4 className="text-lg font-bold text-text mb-3 leading-tight">{news[index].title}</h4>
                        <p className="text-sm text-muted leading-relaxed">{news[index].summary}</p>

                        <div className="absolute bottom-0 left-0 w-full h-1 bg-surface">
                            <div 
                                className="h-full bg-primary transition-all duration-300" 
                                style={{ width: `${((index + 1) / news.length) * 100}%` }}
                            ></div>
                        </div>
                    </div>

                    <div className="flex items-center justify-between mt-4">
                        <Button variant="secondary" size="sm" onClick={handlePrev} className="h-8 w-8 p-0 rounded-full">
                            <ChevronLeft className="w-4 h-4" />
                        </Button>
                        <span className="text-xs font-mono text-muted">{index + 1} / {news.length}</span>
                        <Button variant="secondary" size="sm" onClick={handleNext} className="h-8 w-8 p-0 rounded-full">
                            <ChevronRight className="w-4 h-4" />
                        </Button>
                    </div>
                </div>
            ) : (
                <div className="flex-1 flex items-center justify-center text-muted text-sm">
                    No news available. Try refreshing.
                </div>
            )}
        </div>
    );
};

