// --- COMPONENT: FINANCIAL HEALTH WIDGET ---
const FinancialWidget: React.FC<{ lang: string }> = ({ lang }) => {
    const [grossIncome, setGrossIncome] = useState(85000); // Monthly Gross
    const [needs, setNeeds] = useState(25000);
    const [wants, setWants] = useState(12000);
    const [includeTax, setIncludeTax] = useState(true);

    // --- Tax Calculation Logic (FY 2024-25 New Regime) ---
    const calculateMonthlyTax = (monthlyGross: number) => {
        const annualIncome = monthlyGross * 12;
        const stdDeduction = 75000; // Assuming salaried for this widget default
        const taxableIncome = Math.max(0, annualIncome - stdDeduction);

        let annualTax = 0;
        let slabInfo = "Nil";

        if (taxableIncome <= 700000) {
            annualTax = 0;
            slabInfo = "Rebate u/s 87A";
        } else {
            // 0-3L: 0
            // 3-7L: 5%
            if (taxableIncome > 300000) annualTax += Math.min(taxableIncome - 300000, 400000) * 0.05;
            // 7-10L: 10%
            if (taxableIncome > 700000) annualTax += Math.min(taxableIncome - 700000, 300000) * 0.10;
            // 10-12L: 15%
            if (taxableIncome > 1000000) annualTax += Math.min(taxableIncome - 1000000, 200000) * 0.15;
            // 12-15L: 20%
            if (taxableIncome > 1200000) annualTax += Math.min(taxableIncome - 1200000, 300000) * 0.20;
            // >15L: 30%
            if (taxableIncome > 1500000) annualTax += (taxableIncome - 1500000) * 0.30;

            // Determine highest slab for display
            if (taxableIncome > 1500000) slabInfo = "30% Slab";
            else if (taxableIncome > 1200000) slabInfo = "20% Slab";
            else if (taxableIncome > 1000000) slabInfo = "15% Slab";
            else if (taxableIncome > 700000) slabInfo = "10% Slab";
            else slabInfo = "5% Slab";
        }

        const cess = annualTax * 0.04;
        return { 
            monthlyTax: (annualTax + cess) / 12,
            slabInfo 
        };
    };

    const taxData = calculateMonthlyTax(grossIncome);
    const appliedTax = includeTax ? taxData.monthlyTax : 0;

    // Balance calculation
    const savings = Math.max(0, grossIncome - appliedTax - needs - wants);

    // Chart Data Construction
    const data = [
        ...(includeTax && appliedTax > 0 ? [{ name: 'Tax', value: appliedTax, color: '#EAB308' }] : []), // Yellow
        { name: 'Needs', value: needs, color: '#3B82F6' }, // Blue
        { name: 'Wants', value: wants, color: '#EF4444' }, // Red
        { name: 'Savings', value: savings, color: '#10B981' }, // Green
    ];

    // Status logic
    const savingsPct = Math.round((savings / grossIncome) * 100) || 0;
    const status = savingsPct >= 20 ? 'Healthy' : 'Tight';

    return (
        <Card className="flex flex-col w-full overflow-hidden transition-all duration-300">
            {/* Header Section */}
            <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between mb-4 gap-2 border-b border-border pb-3">
                <h3 className="font-bold flex items-center gap-2 text-lg">
                    <DollarSign className="w-5 h-5 text-green-500" />
                    Financial Health
                </h3>
                <div className="flex items-center gap-2 w-full sm:w-auto justify-between sm:justify-end">
                    <label className="flex items-center gap-2 text-xs font-medium cursor-pointer bg-surface border border-border px-3 py-1.5 rounded-full hover:bg-black/5 dark:hover:bg-white/5 transition-colors select-none">
                        <input 
                            type="checkbox" 
                            checked={includeTax} 
                            onChange={e => setIncludeTax(e.target.checked)}
                            className="w-3.5 h-3.5 text-primary rounded focus:ring-primary accent-primary"
                        />
                        Deduct Tax
                    </label>
                    <Badge variant={status === 'Healthy' ? 'success' : 'warning'}>{status}</Badge>
                </div>
            </div>

            {/* Main Content */}
            <div className="flex flex-col gap-4">

                {/* Chart - Height Constrained */}
                <div className="relative w-full h-[200px] flex-shrink-0">
                    <ResponsiveContainer width="100%" height="100%">
                        <PieChart margin={{ top: 0, left: 0, right: 0, bottom: 0 }}>
                            <Pie
                                data={data}
                                cx="50%"
                                cy="50%"
                                innerRadius={55}
                                outerRadius={80}
                                paddingAngle={3}
                                dataKey="value"
                                stroke="none"
                            >
                                {data.map((entry, index) => (
                                    <Cell key={`cell-${index}`} fill={entry.color} />
                                ))}
