// --- COMPONENT: FINANCIAL HEALTH WIDGET ---
const FinancialWidget: React.FC<{ lang: string }> = ({ lang }) => {
    const [grossIncome, setGrossIncome] = useState(85000); // Monthly Gross
    const [needs, setNeeds] = useState(25000);
    const [wants, setWants] = useState(12000);
    const [includeTax, setIncludeTax] = useState(true);

    // --- Tax Calculation Logic (FY 2024-25 New Regime) ---
    const calculateMonthlyTax = (monthlyGross: number) => {
        const annualIncome = monthlyGross * 12;
        const stdDeduction = 75000; // Assuming salaried for this widget default
        const taxableIncome = Math.max(0, annualIncome - stdDeduction);

        let annualTax = 0;
        let slabInfo = "Nil";

        if (taxableIncome <= 700000) {
            annualTax = 0;
            slabInfo = "Rebate u/s 87A";
        } else {
            // 0-3L: 0
            // 3-7L: 5%
            if (taxableIncome > 300000) annualTax += Math.min(taxableIncome - 300000, 400000) * 0.05;
            // 7-10L: 10%
            if (taxableIncome > 700000) annualTax += Math.min(taxableIncome - 700000, 300000) * 0.10;
            // 10-12L: 15%
            if (taxableIncome > 1000000) annualTax += Math.min(taxableIncome - 1000000, 200000) * 0.15;
            // 12-15L: 20%
            if (taxableIncome > 1200000) annualTax += Math.min(taxableIncome - 1200000, 300000) * 0.20;
            // >15L: 30%
            if (taxableIncome > 1500000) annualTax += (taxableIncome - 1500000) * 0.30;

            // Determine highest slab for display
            if (taxableIncome > 1500000) slabInfo = "30% Slab";
            else if (taxableIncome > 1200000) slabInfo = "20% Slab";
            else if (taxableIncome > 1000000) slabInfo = "15% Slab";
            else if (taxableIncome > 700000) slabInfo = "10% Slab";
            else slabInfo = "5% Slab";
        }

        const cess = annualTax * 0.04;
        return { 
            monthlyTax: (annualTax + cess) / 12,
            slabInfo 
        };
    };

    const taxData = calculateMonthlyTax(grossIncome);
    const appliedTax = includeTax ? taxData.monthlyTax : 0;

    // Balance calculation
    const savings = Math.max(0, grossIncome - appliedTax - needs - wants);

    // Chart Data Construction
    const data = [
        ...(includeTax && appliedTax > 0 ? [{ name: 'Tax', value: appliedTax, color: '#EAB308' }] : []), // Yellow
        { name: 'Needs', value: needs, color: '#3B82F6' }, // Blue
        { name: 'Wants', value: wants, color: '#EF4444' }, // Red
        { name: 'Savings', value: savings, color: '#10B981' }, // Green
    ];

    // Status logic
    const savingsPct = Math.round((savings / grossIncome) * 100) || 0;
    const status = savingsPct >= 20 ? 'Healthy' : 'Tight';

    return (
        <Card className="flex flex-col w-full overflow-hidden transition-all duration-300">
            {/* Header Section */}
            <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between mb-4 gap-2 border-b border-border pb-3">
                <h3 className="font-bold flex items-center gap-2 text-lg">
                    <DollarSign className="w-5 h-5 text-green-500" />
                    Financial Health
                </h3>
                <div className="flex items-center gap-2 w-full sm:w-auto justify-between sm:justify-end">
                    <label className="flex items-center gap-2 text-xs font-medium cursor-pointer bg-surface border border-border px-3 py-1.5 rounded-full hover:bg-black/5 dark:hover:bg-white/5 transition-colors select-none">
                        <input 
                            type="checkbox" 
                            checked={includeTax} 
                            onChange={e => setIncludeTax(e.target.checked)}
                            className="w-3.5 h-3.5 text-primary rounded focus:ring-primary accent-primary"
                        />
                        Deduct Tax
                    </label>
                    <Badge variant={status === 'Healthy' ? 'success' : 'warning'}>{status}</Badge>
                </div>
            </div>

            {/* Main Content */}
            <div className="flex flex-col gap-4">

                {/* Chart - Height Constrained */}
                <div className="relative w-full h-[200px] flex-shrink-0">
                    <ResponsiveContainer width="100%" height="100%">
                        <PieChart margin={{ top: 0, left: 0, right: 0, bottom: 0 }}>
                            <Pie
                                data={data}
                                cx="50%"
                                cy="50%"
                                innerRadius={55}
                                outerRadius={80}
                                paddingAngle={3}
                                dataKey="value"
                                stroke="none"
                            >
                                {data.map((entry, index) => (
                                    <Cell key={`cell-${index}`} fill={entry.color} />
                                ))}
                            </Pie>
                            <RechartsTooltip 
                                formatter={(value: number) => [`₹${Math.round(value).toLocaleString()}`, '']}
                                contentStyle={{ backgroundColor: 'var(--color-surface)', borderColor: 'var(--color-border)', borderRadius: '8px', fontSize: '12px' }}
                            />
                            <Legend verticalAlign="middle" align="right" layout="vertical" iconType="circle" wrapperStyle={{ fontSize: '11px', right: 0 }} />
                        </PieChart>
                    </ResponsiveContainer>
                    {/* Center Text */}
                    <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none pr-16">
                        <span className="text-[10px] text-muted font-medium uppercase tracking-wider">Savings</span>
                        <span className="text-xl font-bold text-green-500">₹{Math.round(savings).toLocaleString()}</span>
                    </div>
                </div>

                {/* Input Fields Grid */}
                <div className="grid grid-cols-2 gap-3">

                    {/* Row 1: Income */}
                    <div className="col-span-2">
                        <Label className="text-xs">Monthly Gross Income</Label>
                        <div className="relative">
                            <span className="absolute left-3 top-1/2 -translate-y-1/2 text-muted text-xs">₹</span>
                            <Input 
                                type="number" 
                                className="pl-7 h-9 text-sm font-semibold" 
                                value={grossIncome} 
                                onChange={e => setGrossIncome(Number(e.target.value))} 
                            />
                        </div>
                    </div>

                    {/* Row 2: Tax (Conditional) */}
                    {includeTax && (
                        <div className="col-span-2 animate-in slide-in-from-top-2 duration-300">
                             <div className="flex justify-between items-center mb-1">
                                <Label className="text-xs text-yellow-600 mb-0">Estimated Tax Deduction</Label>
                                <span className="text-[10px] bg-yellow-100 dark:bg-yellow-900/30 text-yellow-600 px-1.5 rounded">{taxData.slabInfo}</span>
                             </div>
                             <div className="h-9 px-3 bg-yellow-500/5 border border-yellow-500/20 rounded-lg flex items-center justify-between text-yellow-600 text-sm font-medium">
                                 <span className="text-xs opacity-80">Central + Cess</span>
                                 <span>- ₹{Math.round(taxData.monthlyTax).toLocaleString()}</span>
                             </div>
                        </div>
                    )}

                    {/* Row 3: Needs & Wants */}
                    <div className="col-span-1">
                        <Label className="text-xs text-blue-400">Needs (Fixed)</Label>
                        <div className="relative">
                            <span className="absolute left-3 top-1/2 -translate-y-1/2 text-muted text-xs">₹</span>
                            <Input type="number" className="pl-7 h-9 text-sm" value={needs} onChange={e => setNeeds(Number(e.target.value))} />
                        </div>
                    </div>

                    <div className="col-span-1">
                        <Label className="text-xs text-red-400">Wants (Var)</Label>
                         <div className="relative">
                            <span className="absolute left-3 top-1/2 -translate-y-1/2 text-muted text-xs">₹</span>
                            <Input type="number" className="pl-7 h-9 text-sm" value={wants} onChange={e => setWants(Number(e.target.value))} />
                        </div>
                    </div>

                    {/* Row 4: Final Savings */}
                    <div className="col-span-2 mt-1">
                        <Label className="text-xs text-green-500">Projected Monthly Savings</Label>
                        <div className="h-10 flex items-center justify-between px-4 bg-green-500/10 border border-green-500/20 rounded-lg text-green-500 font-bold text-base shadow-sm">
                            <span>Net Balance</span>
                            <span>₹{Math.round(savings).toLocaleString()}</span>
                        </div>
                    </div>

                </div>
            </div>
        </Card>
    );
};

// --- COMPONENT: SIP CALCULATOR ---
const SIPCalculator: React.FC = () => {
    const [monthly, setMonthly] = useState(5000);
    const [rate, setRate] = useState(12);
    const [years, setYears] = useState(10);

    const i = rate / 100 / 12;
    const n = years * 12;
    // FV = P * [ (1+i)^n - 1 ] * (1+i) / i
    const futureValue = monthly * ((Math.pow(1 + i, n) - 1) / i) * (1 + i);
    const totalInvested = monthly * n;

    return (
        <div className="space-y-4">
            <div className="grid grid-cols-3 gap-2 text-xs">
                <div>
                    <Label>Monthly (₹)</Label>
                    <Input type="number" value={monthly} onChange={e => setMonthly(Number(e.target.value))} />
                </div>
                <div>
                    <Label>Return (%)</Label>
                    <Input type="number" value={rate} onChange={e => setRate(Number(e.target.value))} />
                </div>
                <div>
                    <Label>Years</Label>
                    <Input type="number" value={years} onChange={e => setYears(Number(e.target.value))} />
                </div>
            </div>
            <div className="p-3 bg-surface border border-border rounded-lg text-center">
                <p className="text-xs text-muted">Estimated Value</p>
                <p className="text-xl font-bold text-green-500">₹ {Math.round(futureValue).toLocaleString()}</p>
                <p className="text-xs text-muted mt-1">Invested: ₹ {totalInvested.toLocaleString()}</p>
            </div>
        </div>
    );
};

// --- COMPONENT: TAX ASSISTANT ---
const TaxAssistant: React.FC = () => {
    const [income, setIncome] = useState(1200000);
    const [isSalaried, setIsSalaried] = useState(true);
    const [showBreakdown, setShowBreakdown] = useState(false);

    // Latest Budget FY 2024-25 (AY 2025-26) - New Regime
    const calculateTax = () => {
        const stdDeduction = isSalaried ? 75000 : 0;
        const taxableIncome = Math.max(0, income - stdDeduction);

        let tax = 0;
        let breakdown: {label: string, amount: number}[] = [];

        if (taxableIncome <= 700000) {
            return { tax: 0, cess: 0, total: 0, taxableIncome, breakdown: [{ label: "Rebate u/s 87A applied (Income ≤ ₹7L)", amount: 0 }] };
        }

        if (taxableIncome > 300000) {
             const slab2 = Math.min(taxableIncome, 700000) - 300000;
             const tax2 = slab2 * 0.05;
             tax += tax2;
             if(tax2 > 0) breakdown.push({ label: "₹3L - ₹7L (5%)", amount: tax2 });
        }
        if (taxableIncome > 700000) {
            const slab3 = Math.min(taxableIncome, 1000000) - 700000;
            const tax3 = slab3 * 0.10;
            tax += tax3;
            if(tax3 > 0) breakdown.push({ label: "₹7L - ₹10L (10%)", amount: tax3 });
        }
        if (taxableIncome > 1000000) {
            const slab4 = Math.min(taxableIncome, 1200000) - 1000000;
            const tax4 = slab4 * 0.15;
            tax += tax4;
            if(tax4 > 0) breakdown.push({ label: "₹10L - ₹12L (15%)", amount: tax4 });
        }
        if (taxableIncome > 1200000) {
             const slab5 = Math.min(taxableIncome, 1500000) - 1200000;
             const tax5 = slab5 * 0.20;
             tax += tax5;
             if(tax5 > 0) breakdown.push({ label: "₹12L - ₹15L (20%)", amount: tax5 });
        }
        if (taxableIncome > 1500000) {
            const slab6 = taxableIncome - 1500000;
            const tax6 = slab6 * 0.30;
            tax += tax6;
             if(tax6 > 0) breakdown.push({ label: "> ₹15L (30%)", amount: tax6 });
        }

        const cess = tax * 0.04;
        return { tax, cess, total: tax + cess, taxableIncome, breakdown };
    };

    const res = calculateTax();

    return (
        <div className="space-y-4">
             <div className="flex justify-between items-center border-b border-border pb-2">
                 <Label className="mb-0">FY 2024-25 (New Regime)</Label>
                 <Badge variant="info">Default</Badge>
             </div>

             <div className="space-y-3">
                 <div>
                    <div className="flex justify-between items-center mb-1">
                        <Label>Annual Gross Income</Label>
                        <div className="flex items-center gap-2">
                            <input 
                                type="checkbox" 
                                id="salaried" 
                                checked={isSalaried} 
                                onChange={e => setIsSalaried(e.target.checked)} 
                                className="rounded text-primary focus:ring-primary w-4 h-4"
                            />
                            <label htmlFor="salaried" className="text-xs text-text cursor-pointer select-none">Salaried?</label>
                        </div>
                    </div>
                    <div className="relative">
                        <span className="absolute left-3 top-1/2 -translate-y-1/2 text-muted text-sm">₹</span>
                        <Input 
                            type="number" 
                            className="pl-7" 
                            value={income} 
                            onChange={e => setIncome(Number(e.target.value))} 
                        />
                    </div>
                 </div>

                 <div className="p-4 bg-surface border border-border rounded-lg space-y-3">
                     <div className="flex justify-between text-xs text-muted">
                         <span>Standard Deduction:</span>
                         <span className="text-green-500">- ₹{isSalaried ? '75,000' : '0'}</span>
                     </div>
                     <div className="flex justify-between text-sm font-medium">
                         <span>Taxable Income:</span>
                         <span>₹{res.taxableIncome.toLocaleString()}</span>
                     </div>
                     <div className="border-t border-border my-2"></div>
                     <div className="flex justify-between items-center">
                         <span className="text-sm font-bold">Total Tax:</span>
                         <span className="text-xl font-bold text-red-500">₹ {Math.round(res.total).toLocaleString()}</span>
                     </div>
                 </div>

                 <button 
                    onClick={() => setShowBreakdown(!showBreakdown)}
                    className="w-full text-xs text-primary flex items-center justify-center gap-1 hover:underline"
                 >
                     {showBreakdown ? 'Hide Breakdown' : 'Show Calculation Details'}
                     {showBreakdown ? <ChevronUp className="w-3 h-3" /> : <ChevronDown className="w-3 h-3" />}
                 </button>

                 {showBreakdown && (
                     <div className="bg-background rounded border border-border p-3 space-y-2 text-xs animate-in slide-in-from-top-2">
                        {res.breakdown.map((item, i) => (
                            <div key={i} className="flex justify-between">
                                <span className="text-muted">{item.label}</span>
                                <span>₹{Math.round(item.amount).toLocaleString()}</span>
                            </div>
                        ))}
                        <div className="flex justify-between border-t border-border pt-2 mt-2">
                             <span className="text-muted">Health & Education Cess (4%)</span>
                             <span>₹{Math.round(res.cess).toLocaleString()}</span>
                        </div>
                     </div>
                 )}

                 <div className="text-[10px] text-muted space-y-1 bg-blue-500/5 p-2 rounded">
                     <p>• <strong>Standard Deduction:</strong> ₹75,000 for salaried (Proposed FY24-25).</p>
                     <p>• <strong>Rebate 87A:</strong> No tax if taxable income ≤ ₹7 Lakhs.</p>
                     <p>• <strong>Slabs:</strong> 0-3L (Nil), 3-7L (5%), 7-10L (10%), 10-12L (15%), 12-15L (20%), >15L (30%).</p>
                 </div>
             </div>
        </div>
    );
};

