        setLoading(true);
        try {
            const data = await GeminiService.generateQuizByTopic("Current Affairs & General Studies");
            setQuestions(data);
            setStarted(true);
            setSubmitted(false);
            setAnswers({});
        } catch (e) {
            console.error(e);
        } finally {
