            if (answers[i] === q.correctAnswer) s++;
        });
        setScore(s);
        setSubmitted(true);
    };

    if (loading) return (
        <div className="h-64 flex flex-col items-center justify-center text-muted">
             <Zap className="w-8 h-8 animate-pulse mb-2 text-primary" />
             <p>Generating Today's Quiz...</p>
        </div>
    );

    if (!started) return (
        <div className="text-center py-6">
            <Landmark className="w-12 h-12 mx-auto text-blue-600 mb-3" />
            <h3 className="text-lg font-bold">Daily General Studies Quiz</h3>
            <p className="text-sm text-muted mb-4">Test your knowledge with 5 fresh questions on Current Affairs & GS.</p>
            <Button onClick={startQuiz} className="w-full">Start Practice</Button>
        </div>
    );

    return (
        <div className="space-y-6">
             {!submitted ? (
                 <div className="space-y-6">
                     {questions.map((q, i) => (
                         <div key={i} className="pb-4 border-b border-border last:border-0">
                             <p className="font-medium text-text mb-3">{i+1}. {q.question}</p>
                             <div className="space-y-2">
                                 {q.options.map((opt: string, idx: number) => (
                                     <button
                                        key={idx}
                                        onClick={() => setAnswers(prev => ({...prev, [i]: opt}))}
                                        className={`w-full text-left p-2 rounded-lg text-sm border transition-all ${
                                            answers[i] === opt 
                                            ? 'bg-primary/20 border-primary text-primary' 
                                            : 'bg-background border-border hover:bg-surface'
                                        }`}
                                     >
                                         {opt}
                                     </button>
                                 ))}
                             </div>
                         </div>
                     ))}
                     <Button onClick={handleSubmit} className="w-full">Submit Quiz</Button>
                 </div>
             ) : (
                 <div className="text-center space-y-4">
                     <div className="p-4 bg-surface border border-border rounded-lg">
                         <h3 className="text-xl font-bold mb-1">Score: {score} / {questions.length}</h3>
                         <p className="text-sm text-muted">{score > 3 ? "Excellent Work!" : "Keep Practicing!"}</p>
                     </div>
                     <div className="text-left space-y-4 max-h-64 overflow-y-auto pr-2">
                         {questions.map((q, i) => (
                             <div key={i} className="text-sm border-b border-border pb-2">
                                 <p className="font-medium mb-1">{i+1}. {q.question}</p>
                                 <div className="flex items-center gap-2 mb-1">
                                    {answers[i] === q.correctAnswer ? <CheckCircle className="w-4 h-4 text-green-500"/> : <XCircle className="w-4 h-4 text-red-500"/>}
                                    <span className={answers[i] === q.correctAnswer ? "text-green-500" : "text-red-500"}>
                                        You: {answers[i] || 'Skipped'}
                                    </span>
                                 </div>
                                 {answers[i] !== q.correctAnswer && <p className="text-green-500">Correct: {q.correctAnswer}</p>}
                                 <p className="text-xs text-muted mt-1 bg-black/5 p-2 rounded">{q.explanation}</p>
                             </div>
                         ))}
                     </div>
                     <Button onClick={startQuiz} variant="secondary" className="w-full">Take Another Quiz</Button>
                 </div>
             )}
        </div>
    );
};

// --- COMPONENT: CURRENT AFFAIRS FEED (INTERACTIVE) ---
const CurrentAffairsFeed: React.FC = () => {
    const [news, setNews] = useState<any[]>([]);
    const [loading, setLoading] = useState(false);
    const [index, setIndex] = useState(0);

    const fetchNews = async () => {
        setLoading(true);
        const data = await GeminiService.generateCurrentAffairs();
        if (Array.isArray(data) && data.length > 0) {
            setNews(data);
            setIndex(0);
        } else {
             // Fallback if data is empty (handle errors gracefully)
             setNews([]);
        }
        setLoading(false);
    };

    useEffect(() => {
        fetchNews();
    }, []);

    const handleNext = () => setIndex(prev => (prev + 1) % news.length);
    const handlePrev = () => setIndex(prev => (prev - 1 + news.length) % news.length);

    return (
        <div className="bg-surface border border-border rounded-lg p-4 h-full flex flex-col">
            <div className="flex justify-between items-center mb-4">
                <h3 className="font-bold flex items-center gap-2">
                    <Bell className="w-4 h-4 text-orange-500" />
                    Daily Digest
                </h3>
                <Button variant="ghost" size="sm" onClick={fetchNews} disabled={loading} className="h-6 w-6 p-0 rounded-full">
                     <RefreshCw className={`w-3 h-3 ${loading ? 'animate-spin' : ''}`} />
                </Button>
            </div>

            {loading ? (
                <div className="flex-1 flex flex-col items-center justify-center space-y-3 opacity-50">
                    <div className="w-12 h-12 rounded-full border-2 border-primary border-t-transparent animate-spin"></div>
                    <p className="text-xs text-muted">Curating today's headlines...</p>
                </div>
            ) : news.length > 0 ? (
                <div className="flex-1 flex flex-col">
                    <div className="flex-1 bg-background border border-border rounded-lg p-5 relative overflow-hidden transition-all duration-300 flex flex-col">
                        <div className="flex justify-between items-start mb-3">
                            <Badge variant={news[index].category === 'Politics' ? 'warning' : 'info'}>
                                {news[index].category}
                            </Badge>
                            <span className="text-[10px] text-muted uppercase tracking-wider">{news[index].importance} Impact</span>
                        </div>
                        <h4 className="text-lg font-bold text-text mb-3 leading-tight">{news[index].title}</h4>
                        <p className="text-sm text-muted leading-relaxed mb-3">{news[index].summary}</p>

                        {/* Source Attribution */}
                        {news[index].source && (
                            <div className="flex items-center gap-2 text-xs text-muted/70 mt-auto pt-3 border-t border-border/50">
                                <span>Source: {news[index].source}</span>
                                {news[index].url && (
                                    <a href={news[index].url} target="_blank" rel="noopener noreferrer" className="text-primary hover:underline flex items-center gap-1 ml-auto">
                                        <ExternalLink className="w-3 h-3" /> Read More
                                    </a>
                                )}
                            </div>
                        )}

                        <div className="absolute bottom-0 left-0 w-full h-1 bg-surface">
                            <div 
                                className="h-full bg-primary transition-all duration-300" 
                                style={{ width: `${((index + 1) / news.length) * 100}%` }}
                            ></div>
                        </div>
                    </div>

                    <div className="flex items-center justify-between mt-4">
                        <Button variant="secondary" size="sm" onClick={handlePrev} className="h-8 w-8 p-0 rounded-full">
                            <ChevronLeft className="w-4 h-4" />
                        </Button>
                        <span className="text-xs font-mono text-muted">{index + 1} / {news.length}</span>
                        <Button variant="secondary" size="sm" onClick={handleNext} className="h-8 w-8 p-0 rounded-full">
                            <ChevronRight className="w-4 h-4" />
                        </Button>
                    </div>
                </div>
            ) : (
                <div className="flex-1 flex flex-col items-center justify-center text-muted text-sm gap-2">
                    <p>No news available.</p>
                    <Button variant="ghost" size="sm" onClick={fetchNews} className="text-xs text-primary">Try Refreshing</Button>
                </div>
            )}
        </div>
    );
};

