    const fileInputRef = useRef<HTMLInputElement>(null);

    // Header Config
    const [schoolName, setSchoolName] = useState('St. Xavier\'s High School');
    const [logoUrl, setLogoUrl] = useState(''); // Just a text field for URL or base64 placeholder for now
    const [examDuration, setExamDuration] = useState('2 Hours');

    // Question Counts
    const [qaSettings, setQaSettings] = useState({
        fillInBlanks: { enabled: false, count: 5 },
        mcq: { enabled: true, count: 10 },
        short2: { enabled: true, count: 5 },
        short5: { enabled: true, count: 4 },
        long10: { enabled: true, count: 2 },
        long15: { enabled: false, count: 1 },
    });

    const [loading, setLoading] = useState(false);
    const [result, setResult] = useState<any>(null);

    const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
             const reader = new FileReader();
             reader.onload = (evt) => {
                 const result = evt.target?.result as string;
                 const match = result.match(/^data:(.*);base64,(.*)$/);
                 if (match) {
                     setUploadedFile({
                         name: file.name,
                         mimeType: match[1],
                         data: match[2]
                     });
                 }
             };
             reader.readAsDataURL(file);
        }
    };

    const handleGenerate = async () => {
        if (!topic && !uploadedFile) {
            addToast("Please enter a topic or upload a file.", "error");
            return;
        }
        setLoading(true);

        const config: QAConfig = {
            fillInBlanks: qaSettings.fillInBlanks.enabled ? qaSettings.fillInBlanks.count : 0,
            mcq: qaSettings.mcq.enabled ? qaSettings.mcq.count : 0,
            short2: qaSettings.short2.enabled ? qaSettings.short2.count : 0,
            short5: qaSettings.short5.enabled ? qaSettings.short5.count : 0,
            long10: qaSettings.long10.enabled ? qaSettings.long10.count : 0,
            long15: qaSettings.long15.enabled ? qaSettings.long15.count : 0,
        };

        try {
            const res = await GeminiService.generatePaper(
                topic, 
                grade, 
                uploadedFile ? { mimeType: uploadedFile.mimeType, data: uploadedFile.data } : undefined,
                config
            );
            setResult(res);
            addToast("Paper Generated Successfully", "success");
        } catch (e) {
            addToast("Failed to generate paper", "error");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
            {/* Configuration Panel */}
            <div className="lg:col-span-1 space-y-6">
                <Card title="Paper Configuration">
                    <div className="space-y-4">
                        <div>
                            <Label>Institution Name</Label>
                            <Input value={schoolName} onChange={e => setSchoolName(e.target.value)} />
                        </div>
                        <div className="grid grid-cols-2 gap-2">
                            <div>
                                <Label>{t.grade}</Label>
                                <Select value={grade} onChange={e => setGrade(e.target.value)}>
                                    {[6,7,8,9,10,11,12].map(g => <option key={g} value={g}>Class {g}</option>)}
                                </Select>
                            </div>
                            <div>
                                <Label>Duration</Label>
                                <Input value={examDuration} onChange={e => setExamDuration(e.target.value)} />
                            </div>
                        </div>

                        {/* Source Material */}
                        <div className="p-3 bg-background border border-border rounded-lg">
                            <Label className="mb-2">Study Material (Source)</Label>
                            {uploadedFile ? (
                                <div className="flex items-center justify-between p-2 bg-primary/10 rounded border border-primary/20">
                                    <div className="flex items-center gap-2 overflow-hidden">
                                        <FileIcon className="w-4 h-4 text-primary shrink-0" />
                                        <span className="text-xs text-text truncate">{uploadedFile.name}</span>
                                    </div>
                                    <button onClick={() => setUploadedFile(null)} className="text-muted hover:text-red-500">
                                        <X className="w-4 h-4" />
                                    </button>
                                </div>
                            ) : (
                                <div className="space-y-2">
                                    <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" accept=".pdf,image/*" />
                                    <Button variant="secondary" size="sm" className="w-full text-xs" onClick={() => fileInputRef.current?.click()}>
                                        <Upload className="w-3 h-3 mr-2" /> Upload PDF/Image
                                    </Button>
                                    <div className="text-center text-xs text-muted">- OR -</div>
                                    <Textarea 
                                        placeholder="Enter Topic / Syllabus Topics" 
                                        rows={2} 
                                        value={topic}
                                        onChange={e => setTopic(e.target.value)}
                                        className="text-xs"
                                    />
                                </div>
                            )}
                        </div>

                        {/* Question Config */}
                        <div className="p-3 bg-background border border-border rounded-lg space-y-3">
                            <Label className="flex items-center gap-2"><Settings2 className="w-3 h-3" /> Question Distribution</Label>
                            <div className="space-y-2 max-h-60 overflow-y-auto pr-1">
                                {[
                                    { id: 'fillInBlanks', label: 'Fill in Blanks' },
                                    { id: 'mcq', label: 'MCQs (1 Mark)' },
                                    { id: 'short2', label: 'Very Short (2 Marks)' },
                                    { id: 'short5', label: 'Short (5 Marks)' },
                                    { id: 'long10', label: 'Long (10 Marks)' },
                                    { id: 'long15', label: 'Essay (15 Marks)' }
                                ].map((type) => {
                                    const key = type.id as keyof typeof qaSettings;
                                    const setting = qaSettings[key];
                                    return (
                                        <div key={key} className="flex items-center justify-between text-xs">
                                             <div className="flex items-center gap-2">
                                                <input 
                                                    type="checkbox" 
                                                    checked={setting.enabled}
                                                    onChange={(e) => setQaSettings(prev => ({ ...prev, [key]: { ...prev[key], enabled: e.target.checked } }))}
                                                    className="rounded text-primary focus:ring-primary"
                                                />
                                                <span>{type.label}</span>
                                             </div>
                                             {setting.enabled && (
                                                <input 
                                                    type="number" min="1" max="50"
                                                    value={setting.count}
                                                    onChange={(e) => setQaSettings(prev => ({ ...prev, [key]: { ...prev[key], count: parseInt(e.target.value) || 1 } }))}
                                                    className="w-12 px-1 py-0.5 border rounded text-center bg-surface"
                                                />
                                             )}
                                        </div>
                                    )
                                })}
                            </div>
                        </div>

                        <Button onClick={handleGenerate} loading={loading} className="w-full">
                            Generate Paper
                        </Button>
                    </div>
                </Card>
            </div>

            {/* Preview Panel */}
            <div className="lg:col-span-2">
                <Card className="h-full min-h-[600px] flex flex-col bg-white text-black relative">
                    {result ? (
                        <div className="flex-1 p-8 font-serif overflow-y-auto">
                            {/* Paper Header */}
                            <div className="border-b-2 border-black pb-4 mb-6 text-center">
                                <h1 className="text-2xl font-bold uppercase tracking-wide">{schoolName}</h1>
                                <div className="flex justify-between mt-4 font-bold text-sm border-t border-b border-black py-2">
                                    <span>Subject: {topic || "General Assessment"}</span>
                                    <span>Grade: {grade}</span>
                                    <span>Time: {examDuration}</span>
                                    <span>Max Marks: {result.maxMarks || 100}</span>
                                </div>
                                <div className="text-left mt-2 text-xs italic">
                                    <strong>Instructions:</strong>
                                    <ul className="list-disc list-inside">
                                        {result.instructions?.map((inst: string, i: number) => <li key={i}>{inst}</li>) || <li>All questions are compulsory.</li>}
                                    </ul>
                                </div>
                            </div>

                            {/* Questions */}
                            <div className="space-y-6">
                                {result.sections?.map((section: any, idx: number) => (
                                    <div key={idx}>
                                        <h3 className="font-bold text-lg mb-2 border-b border-gray-300 inline-block uppercase">{section.name} ({section.questions.length * section.marksPerQuestion} Marks)</h3>
                                        <div className="space-y-3 pl-2">
                                            {section.questions.map((q: any, qIdx: number) => (
                                                <div key={qIdx} className="mb-2 break-inside-avoid">
                                                    <div className="flex gap-2">
                                                        <span className="font-bold text-sm">{qIdx + 1}.</span>
                                                        <span className="text-sm flex-1">{q.question} <span className="float-right font-bold text-xs">[{section.marksPerQuestion}]</span></span>
                                                    </div>
                                                    {q.options && (
                                                        <div className="grid grid-cols-2 gap-x-4 gap-y-1 mt-1 ml-6 text-sm">
                                                            {q.options.map((opt: string, oI: number) => (
                                                                <div key={oI}>{String.fromCharCode(97+oI)}) {opt}</div>
                                                            ))}
                                                        </div>
                                                    )}
                                                </div>
                                            ))}
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </div>
                    ) : (
                        <div className="flex-1 flex flex-col items-center justify-center text-gray-400">
                             <FileText className="w-16 h-16 mb-4 opacity-20" />
                             <p>Configure and generate to see the preview here.</p>
                        </div>
                    )}

                    {result && (
                         <div className="absolute top-4 right-4 print:hidden">
                             <Button size="sm" onClick={() => window.print()}>
                                 <Printer className="w-4 h-4 mr-2" /> Print / Save PDF
                             </Button>
                         </div>
                    )}
                </Card>
            </div>
            <style>{`
                @media print {
                    body * { visibility: hidden; }
                    .bg-white, .bg-white * { visibility: visible; }
                    .bg-white { position: absolute; left: 0; top: 0; width: 100%; height: 100%; margin: 0; padding: 0; overflow: visible; }
                    .print\\:hidden { display: none !important; }
                }
            `}</style>
        </div>
    );
};

