                    <h3 className="text-lg font-semibold text-text">{title}</h3>
                    <button onClick={onClose} className="text-muted hover:text-text"><X className="w-5 h-5" /></button>
                </div>
                <div className="p-4">
                    {children}
                </div>
            </div>
        </div>
    );
};

