const MockInterview: React.FC = () => {
    const [messages, setMessages] = useState<{role: 'ai' | 'user', text: string}[]>([
        { role: 'ai', text: 'Hello! I am your AI Interviewer. Tell me about yourself.' }
    ]);
    const [input, setInput] = useState('');

    const handleSend = () => {
        if (!input.trim()) return;
        const newMessages = [...messages, { role: 'user' as const, text: input }];
        setMessages(newMessages);
        setInput('');

        // Simulating AI response
        setTimeout(() => {
            setMessages([...newMessages, { role: 'ai', text: "That's interesting. What is your greatest strength?" }]);
        }, 1000);
    };

    return (
        <Card title="Mock Interview Coach" className="h-[500px] flex flex-col">
            <div className="flex-1 overflow-y-auto space-y-4 mb-4 pr-2">
                {messages.map((m, i) => (
                    <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                        <div className={`max-w-[80%] p-3 rounded-lg text-sm ${m.role === 'user' ? 'bg-primary text-white' : 'bg-surface border border-border text-text'}`}>
                            {m.text}
                        </div>
                    </div>
                ))}
            </div>
            <div className="flex gap-2">
                <Textarea 
                    value={input} 
                    onChange={e => setInput(e.target.value)} 
                    placeholder="Type your answer..." 
                    className="min-h-[50px] resize-none w-full"
                    onKeyDown={e => e.key === 'Enter' && !e.shiftKey && (e.preventDefault(), handleSend())}
                />
                <Button onClick={handleSend}><MessageSquare className="w-4 h-4" /></Button>
            </div>
        </Card>
    );
};

const CTCDecoder: React.FC = () => {
    const [ctc, setCtc] = useState(1200000);

    // Simple logic for Indian salary approx
    const monthlyGross = ctc / 12;
    const pf = Math.min(monthlyGross * 0.12, 1800);
    const tax = monthlyGross > 100000 ? (monthlyGross * 0.15) : (monthlyGross * 0.05); // Rough calc
    const inHand = monthlyGross - pf - tax - 200; // Prof tax

    return (
        <Card title="CTC Decoder">
            <div className="space-y-4">
                <div>
                    <Label>Annual CTC (₹)</Label>
                    <Input type="number" value={ctc} onChange={e => setCtc(Number(e.target.value))} className="w-full" />
                </div>
                <div className="p-4 bg-surface border border-border rounded-lg space-y-2">
                    <div className="flex justify-between text-sm"><span className="text-muted">Monthly Gross</span><span>₹{Math.round(monthlyGross).toLocaleString()}</span></div>
                    <div className="flex justify-between text-sm text-red-400"><span className="text-muted">Est. Deductions (PF/Tax)</span><span>- ₹{Math.round(pf + tax + 200).toLocaleString()}</span></div>
                    <div className="flex justify-between text-lg font-bold border-t border-border pt-2 mt-2"><span className="text-text">In-Hand (Est.)</span><span className="text-green-500">₹{Math.round(inHand).toLocaleString()}</span></div>
                </div>
            </div>
        </Card>
    );
};

