    const inHand = monthlyGross - pf - tax - 200; // Prof tax

    return (
        <Card title={t.ctcDecoder}>
            <div className="space-y-4">
                <div>
                    <Label>{t.annualCTC}</Label>
                    <Input type="number" value={ctc} onChange={e => setCtc(Number(e.target.value))} className="w-full" />
