                    <div className="absolute inset-0 backface-hidden bg-surface border-2 border-primary/20 p-8 rounded-3xl shadow-xl flex flex-col items-center justify-center text-center hover:border-primary/50 transition-colors">
                         <div className="flex-1 flex items-center justify-center">
